"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:21:\"WordPress.org España\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:24:\"https://es.wordpress.org\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:5:\"width\";a:1:{i:0;a:5:{s:4:\"data\";s:2:\"32\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:6:\"height\";a:1:{i:0;a:5:{s:4:\"data\";s:2:\"32\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}}s:4:\"item\";a:10:{i:0;a:6:{s:4:\"data\";s:76:\"\n		\n		\n					\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:78:\"¡Participa en el Summer Photo Contest y deja que tus fotos hablen del verano!\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:112:\"https://es.wordpress.org/2025/07/21/participa-en-el-summer-photo-contest-y-deja-que-tus-fotos-hablen-del-verano/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:120:\"https://es.wordpress.org/2025/07/21/participa-en-el-summer-photo-contest-y-deja-que-tus-fotos-hablen-del-verano/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 21 Jul 2025 10:45:25 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:9:\"Comunidad\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:7:\"General\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://es.wordpress.org/?p=693933\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:89:\"El verano es para vivirlo… ¡y para fotografiarlo!\n\nEn WordPress sabemos que así es...\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:10:\"Nilo Velez\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:4439:\"\n<p>El verano es para vivirlo… ¡y para fotografiarlo! Desde <strong><a href=\"https://www.meetup.com/es-ES/quedadas-wordpress-en-espanol/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">Quedadas WordPress</a></strong>, el grupo de meetups online de la comunidad de WordPress española, te invitamos a formar parte del <strong>Summer Photo Contest</strong>, un concurso pensado para celebrar el verano y, al mismo tiempo, ayudar a que crezca uno de los proyectos más bonitos del ecosistema WordPress: el <a href=\"https://wordpress.org/photos/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">WordPress Photo Directory</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">¿Qué es el WordPress Photo Directory?</h2>\n\n\n\n<p>Si aún no lo conoces, el <strong>WordPress Photo Directory</strong> es una colección de fotos libres, gratuitas y colaborativas, 100% hecha por personas como tú. Todas las imágenes están bajo licencia <a href=\"https://creativecommons.org/public-domain/cc0/\" target=\"_blank\" rel=\"noreferrer noopener\">CC0</a>, lo que significa que cualquiera puede usarlas, modificarlas o compartirlas sin pedir permiso, incluso con fines comerciales.</p>\n\n\n\n<p>A diferencia de otras plataformas, aquí no hay algoritmos que te oculten, ni pagos ocultos, ni fórmulas mágicas: si subes una buena foto y cumple las <a href=\"https://wordpress.org/photos/guidelines/\" target=\"_blank\" rel=\"noreferrer noopener\">normas</a>, se publica y queda a disposición del mundo. Así de sencillo. Es una forma de contribuir al proyecto WordPress, aprendiendo fotografía, mostrando tu mirada y regalando tus imágenes a la comunidad.</p>\n\n\n\n<h2 class=\"wp-block-heading\">¿Qué es el Summer Photo Contest?</h2>\n\n\n\n<p>El <strong>Summer Photo Contest</strong> es una iniciativa abierta a todo el mundo que quiera participar. El objetivo es animarte a subir tus mejores fotos veraniegas al WordPress Photo Directory: momentos de descanso, viajes, naturaleza, detalles cotidianos, vida en la ciudad, en la playa o en el campo… ¡todo lo que tenga ese sabor a verano vale!</p>\n\n\n\n<p>Para participar, sólo tienes que subir tus fotos al directorio entre el <strong>1 y el 31 de agosto</strong>, incluyendo la etiqueta <code>#SummerPhotoContest</code> en el formulario. Así de fácil.</p>\n\n\n\n<p>Un jurado formado por fotógrafos y moderadores del propio directorio elegirá las imágenes más destacadas en distintas categorías. Y sí, habrá premios, pensados especialmente para gente a la que le gusta hacer fotos.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Calendario de actividades</h2>\n\n\n\n<p>Además del propio concurso, hemos preparado algunas sesiones en directo para abrir y cerrar el evento, compartir dudas y experiencias, y animarte a participar estés donde estés:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><strong>28 de julio – 12:00 GMT</strong> (14:00 en España): Sesión de apertura (Africa y Asia, en inglés)</li>\n\n\n\n<li><strong>28 de julio – 18:00 GMT</strong> (20:00 en España): Sesión de apertura (España y LATAM, en español)</li>\n\n\n\n<li><strong>28 de julio – 20:00 GMT</strong> (22:00 en España): Sesión de apertura (Estados Unidos y Canadá, en inglés)</li>\n\n\n\n<li><strong>1 de agosto – 00:00 GMT</strong>: ¡Empieza el concurso!</li>\n\n\n\n<li><strong>31 de agosto – 23:59 GMT</strong>: Fin del plazo para subir fotos</li>\n\n\n\n<li><strong>6 de septiembre – 18:00 GMT</strong> (20:00 en España): Sesión de cierre (bilingüe, inglés/español)</li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\">Consigue tu entrada gratuita</h2>\n\n\n\n<p>Todas las actividades se celebran online, y puedes seguirlas desde cualquier lugar del mundo. Para recibir recordatorios, enlaces y novedades del concurso, sólo tienes que <strong>conseguir tu entrada gratuita</strong> en el sitio oficial del evento:</p>\n\n\n\n<p><img src=\"https://s.w.org/images/core/emoji/16.0.1/72x72/1f449.png\" alt=\"👉\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /> <a href=\"https://events.wordpress.org/quedadas/2025/summerphoto\" target=\"_blank\" rel=\"noreferrer noopener\">https://events.wordpress.org/quedadas/2025/summerphoto</a></p>\n\n\n\n<p>No importa si eres fotógrafo profesional o si sólo haces fotos con el móvil cuando te acuerdas. Lo importante es compartir tu mirada y formar parte de esta gran galería colaborativa que es el WordPress Photo Directory.</p>\n\n\n\n<p>Este verano, súmate al reto y deja que tus fotos hablen por ti. ¡Te esperamos!</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:117:\"https://es.wordpress.org/2025/07/21/participa-en-el-summer-photo-contest-y-deja-que-tus-fotos-hablen-del-verano/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:6:\"693933\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:1;a:6:{s:4:\"data\";s:82:\"\n		\n		\n					\n		\n		\n		\n				\n		\n		\n		\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:38:\"¡WordPress 6.8.2 ya está disponible!\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:71:\"https://es.wordpress.org/2025/07/15/wordpress-6-8-2-ya-esta-disponible/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:79:\"https://es.wordpress.org/2025/07/15/wordpress-6-8-2-ya-esta-disponible/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 15 Jul 2025 18:46:06 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:4:{i:0;a:5:{s:4:\"data\";s:15:\"Actualizaciones\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:13:\"Mantenimiento\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:3:\"6.8\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:3;a:5:{s:4:\"data\";s:5:\"6.8.2\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://es.wordpress.org/?p=694611\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:399:\"Esta versión menor incluye correcciones para 20 incidencias principales y 15 problemas con el editor de bloques . Para ver la lista completa de correcciones, consulta el anuncio de la versión candidata a definitiva. WordPress 6.8.2 es una actualización de mantenimiento de ciclo corto. Es posible que se publiquen más actualizaciones de mantenimiento a lo largo de 2025. Si tienes [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:16:\"Fernando Tellado\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:12166:\"\n<p>Esta <strong>versión menor</strong> incluye correcciones para <a href=\"https://core.trac.wordpress.org/query?resolution=fixed&amp;milestone=6.8.2&amp;group=component&amp;col=id&amp;col=summary&amp;col=milestone&amp;col=owner&amp;col=type&amp;col=status&amp;col=priority&amp;order=priority\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">20 incidencias principales</a> y <a href=\"https://github.com/WordPress/gutenberg/pull/70557\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">15 problemas con el editor de bloques</a> . Para ver la lista completa de correcciones, consulta el <a href=\"https://make.wordpress.org/core/2025/07/08/wordpress-6-8-2-rc1-is-now-available/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">anuncio de la versión candidata a definitiva.</a></p>\n\n\n\n<p>WordPress 6.8.2 es una <strong>actualización de mantenimiento</strong> de ciclo corto. Es posible que se publiquen más actualizaciones de mantenimiento a lo largo de 2025.</p>\n\n\n\n<p>Si tienes sitios que admitan actualizaciones automáticas en segundo plano, el proceso de actualización comenzará automáticamente.</p>\n\n\n\n<p>Puedes <a href=\"https://es.wordpress.org/latest-es_ES.zip\" rel=\"nofollow\">descargar WordPress 6.8.2 desde WordPress.org</a> o visitar el escritorio de tu WordPress, hacer clic en «<strong>Actualizaciones</strong>» y luego en «<strong>Actualizar ahora</strong>».</p>\n\n\n\n<p> Para obtener más información sobre esta versión <a href=\"https://wordpress.org/support/wordpress-version/version-6-8-2\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">visita la página de versiones en HelpHub</a> .</p>\n\n\n\n<h2 class=\"wp-block-heading\">Abandono de las actualizaciones de seguridad para las versiones 4.1 a 4.6 de WordPress</h2>\n\n\n\n<p>Esto no está directamente relacionado con la versión de mantenimiento 6.8.2, pero <a href=\"https://wordpress.org/news/2025/06/dropping-security-updates-for-wordpress-versions-4-1-through-4-6/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">las ramas 4.1 a 4.6 han tenido hoy su versión final</a>. </p>\n\n\n\n<p>Estas ramas ya no recibirán ninguna actualización de seguridad.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Gracias a estos colaboradores de WordPress</h2>\n\n\n\n<p>WordPress 6.8.2 lo han liderado <a href=\"https://profiles.wordpress.org/audrasjb/\">Jb Audras</a> ,  <a href=\"https://profiles.wordpress.org/estelaris/\">Estela Rueda</a>  y  <a href=\"https://profiles.wordpress.org/zunaid321/\">Zunaid Amin</a> .</p>\n\n\n\n<p>Un agradecimiento especial a <a href=\"https://profiles.wordpress.org/davidbaumwald/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">@davidbaumwald</a>, <a href=\"https://profiles.wordpress.org/sergeybiryukov/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">@sergeybiryukov</a>, <a href=\"https://profiles.wordpress.org/mamaduka/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">@mamaduka</a>, <a href=\"https://profiles.wordpress.org/wildworks/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">@wildworks</a> y <a href=\"https://profiles.wordpress.org/jorbin/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">@jorbin</a> por su ayuda en tareas específicas del lanzamiento.</p>\n\n\n\n<p>WordPress 6.8.2 no habría sido posible sin las contribuciones de las siguientes 96 personas. </p>\n\n\n\n<p>Su coordinación asíncrona a la hora de convertir ajustes de mantenimiento en una versión estable es un testimonio del potencial y la capacidad de la comunidad WordPress.</p>\n\n\n\n<p class=\"has-white-color has-blueberry-1-background-color has-text-color has-background has-link-color wp-elements-f46b2b90ae2a4e1f14c36bd0573ac884\"><a href=\"https://profiles.wordpress.org/jorbin\">Aaron Jorbin</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/adamsilverstein\">Adam Silverstein</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/zieladam\">Adam Zieliński</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/wildworks\">Aki Hamano</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/alexstine\">Alex Stine</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/anatolbroder\">Anatol Broder</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/afercia\">Andrea Fercia</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/nacin\">Andrew Nacin</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/ankitkumarshah\">Ankit Kumar Shah</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/annezazu\">annezazu</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/azharderaiya\">Azhar Deraiya</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/benjamingosset\">Benjamin Gosset</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/bhubbard\">Brandon Hubbard</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/kraftbj\">Brandon Kraft</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/brhodes\">brhodes</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/poena\">Carolina Nymark</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/czarate\">Chris Zarate</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/courane01\">Courtney Robertson</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/talldanwp\">Daniel Richards</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/darshitrajyaguru97\">Darshit Rajyaguru</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/davidbaumwald\">David Baumwald</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/dmsnell\">Dennis Snell</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/dhruvang21\">Dhruvang21</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/dilipbheda\">Dilip Bheda</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/dd32\">Dion Hulse</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/divinenephron\">Divinenephron</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/dustintechsmith\">Dustintechsmith</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/ericlewis\">Eric Andrew Lewis</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/im3dabasia1\">Eshaan Dabasiya</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/estelaris\">Estela Rueda</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/eherman24\">Evan Herman</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/fabiankaegy\">Fabian Kägy</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/faisalahammad\">Faisal Ahammad</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/flixos90\">Felix Arntz</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/pento\">Gary Pendergast</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/guddu1315\">Gaurang Dabhi</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/mamaduka\">George Mamadashvili</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/gernberg\">Gernberg</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/gziolo\">Greg Ziółkowski</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/harshgajipara\">Harsh Gajipara</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/helgatheviking\">HelgaTheViking</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/abcd95\">Himanshu Pathak</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/audrasjb\">Jb Audras</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/JeffPaul\">Jeffrey Paul</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/jdy68\">Jenny Dupuy</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/luminuu\">Jessica Lyschik</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/jigarpanchal\">Jigar Panchal</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/joedolson\">Joe Dolson</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/joemcgill\">Joe McGill</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/johnbillion\">John Blackbourn</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/mindctrl\">John Parris</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/jonsurrell\">Jon Surrell</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/desrosj\">Jonathan Desrosiers</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/spacedmonkey\">Jonny Harris</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/kausaralm\">Kausar Alam</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/kishanjasani\">Kishan Jasani</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/tyxla\">Marin Atanasov</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/matt\">Matt Mullenweg</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/pfefferle\">Matthias Pfefferle</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/megane9988\">megane9988</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/mosescursor\">Moses Cursor Ssebunya</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/mukesh27\">Mukesh Panchal</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/mwillman1991\">mwillman1991</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/bugnumber9\">Nazar Hotsa</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/nidhidhandhukiya\">nidhidhandhukiya</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/nikunj8866\">Nikunj Hatkar</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/oferlaor\">oferlaor</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/oglekler\">Olga Gleckler</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/swissspidy\">Pascal Birchler</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/paulstanos\">paulstanos</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/peterwilsoncc\">Peter Wilson</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/puggan\">puggan</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/ravigadhiyawp\">Ravi Gadhiya</a>&nbsp;,<a href=\"https://profiles.wordpress.org/youknowriad\">Riad Benguella</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/rollybueno\">Rolly Bueno</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/room34\">room34</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/sainathpoojary\">Sainath Poojary</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/sajjad67\">Sajjad Hossain Sagor</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/Sam_a\">sam_a</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/sandeepdahiya\">Sandeep Dahiya</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/SergeyBiryukov\">Sergey Biryukov</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/shanemuir\">Shane Muirhead</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/siliconforks\">Siliconforks</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/sirlouen\">SirLouen</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/sabernhardt\">Stephen Bernhardt</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/sukhendu2002\">Sukhendu Sekhar Guria</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/karmatosed\">Tammie Lister</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/TobiasBg\">Tobias Bäthge</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/wpsmith\">Travis Smith</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/ugyensupport\">Ugyen Dorji</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/uxl\">uxl</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/westonruter\">Weston Ruter</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/whaze\">whaze</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/getsyash\">Yash B</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/yogeshbhutkar\">Yogesh Bhutkar</a>&nbsp;y&nbsp;<a href=\"https://profiles.wordpress.org/zunaid321\">Zunaid Amin</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">Cómo contribuir</h2>\n\n\n\n<p>Para participar en el desarrollo del núcleo de WordPress, dirígete al Trac, <a href=\"https://core.trac.wordpress.org/report/6\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">elige un tique</a> y únete a la conversación en Slack, en los canales <a href=\"https://wordpress.slack.com/archives/C02RQBWTW\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">#core</a> y <a href=\"https://wordpress.slack.com/archives/C080HLPP2Q6\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">#6-8-release-leads</a>. </p>\n\n\n\n<p>¿Necesitas ayuda? Consulta el <a href=\"https://make.wordpress.org/core/handbook/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">manual para colaboradores del núcleo</a>.</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:76:\"https://es.wordpress.org/2025/07/15/wordpress-6-8-2-ya-esta-disponible/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:6:\"694611\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:2;a:6:{s:4:\"data\";s:70:\"\n		\n		\n					\n		\n		\n		\n				\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:54:\"10 Trucos para Potenciar tus Ventas de Forma Orgánica\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:90:\"https://es.wordpress.org/2025/07/10/10-trucos-para-potenciar-tus-ventas-de-forma-organica/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:98:\"https://es.wordpress.org/2025/07/10/10-trucos-para-potenciar-tus-ventas-de-forma-organica/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 10 Jul 2025 07:11:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://es.wordpress.org/?p=693919\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:59:\"¿Vender más con unos truquitos buenos, rápidos y gratis?\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:12:\"Pilar Garcia\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:14537:\"\n<p>Cuando pensamos en vender online, lo primero que se nos viene a la cabeza es leer un montón de libros, seguir a gurús de las ventas o, quizás, a algún vendehumos, para finalmente llegar a la conclusión de que todo depende del dinero que tenemos para pagar campañas SEM o de contratar a alguien que venda nuestro servicio o producto.&nbsp;</p>\n\n\n\n<p>En conclusión, solemos no arrancar nunca con ninguna de las teorías que hemos leído.&nbsp;</p>\n\n\n\n<p>Sí, existen grandes campañas de SEM y empresas con muchas ganas de vender por ti, pero, ¿y si no queremos o no podemos invertir en publicidad?&nbsp;</p>\n\n\n\n<p>Quiero compartir contigo <strong>10 acciones reales para potenciar tus ventas de forma orgánica</strong>, apoyándote en la potencia de WordPress pero, sobre todo, en el factor humano.</p>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>1. Invita a un buen lead a escribir en tu blog</strong></h2>\n\n\n\n<p>La confianza en ti, en tu producto o en tu empresa es lo que dispara una venta. Generar confianza es difícil si no te conocen. Si, por el contrario, te abres al público y te muestras como una persona relevante, coherente y confiable, lo vas a tener un poco más fácil.</p>\n\n\n\n<p>Una manera de hacer que un lead se fije en ti es invitarle a escribir un artículo en tu blog, siempre y cuando mantengas un blog de calidad y te hayas asegurado de que la persona escogida sabe redactar buenos artículos.</p>\n\n\n\n<p>Si no te conoce, este gesto le obligará a revisar tu web con detenimiento, lo que te brindará la oportunidad de tener un contacto directo y de presentarle tu producto para que el artículo resulte relevante. Si eliges bien, raro sería que esa persona declinara tu oferta.</p>\n\n\n\n<p>Puedes encontrar buenos leads en tu campo —y que, además, sepan escribir buenos artículos— interactuando en redes como LinkedIn. El hecho de poder escribir posts largos te permite observar cómo redactan y trabajan el contenido, y así evaluar si te conviene abrirles la puerta.<br>Alternativamente, busca en tus redes de preferencia o en tu entorno.</p>\n\n\n\n<p>Además, colaborar con personas reconocidas o expertas siempre&nbsp; te va a beneficiar.&nbsp;</p>\n\n\n\n<h3 class=\"wp-block-heading\"><strong>2. Aprovecha cada interacción en redes como si fuera una ‘flecha al objetivo’</strong></h3>\n\n\n\n<p>Las redes son una extensión de tu blog, así que deben transmitir coherencia e información útil. Un perfil bien cuidado (con imágenes de calidad, un buen extracto profesional y enlaces a tu web) puede ser decisivo cuando alguien te descubre.</p>\n\n\n\n<p>Cada post, comentario o respuesta debería acercarte a tu audiencia ideal. Si utilizas las redes con objetivos profesionales, <strong>no des puntada sin hilo</strong>: tu tiempo es oro.<br>Cada vez que interactúes, pregúntate:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>¿Aporta valor?</li>\n\n\n\n<li>¿Me acerca a mi audiencia ideal?</li>\n\n\n\n<li>¿Refuerza mi autoridad?</li>\n</ul>\n\n\n\n<p>Si la respuesta es “no”, a parte de ello o a todo, plantéate cambiar algo o&nbsp; no perder ni un segundo más.<br>Mantén una lista de contactos que interactúen contigo. Acepta a quien ya interactúa o puede llegar a hacerlo, y escribe pensando en ellos.</p>\n\n\n\n<p>Sé relevante en cada post, comentario o “like” que hagas. Aporta valor siempre que puedas.</p>\n\n\n\n<h3 class=\"wp-block-heading\"><strong>3. Alimenta el ego de tus leads</strong></h3>\n\n\n\n<p>A todos nos gusta recibir halagos, sobre todo si son sinceros y si han sido escritos para nosotros exclusivamente. Evita esos mensajes automatizados tan difusos que se redactan para que cualquier persona se sienta interpelada. No hay ni uno que pase el filtro.</p>\n\n\n\n<p>Pide consejo a tu público/ objetivo o lead sobre cuestiones relevantes. Por ejemplo, podrías empezar con:<br><br>“Hola X, en un caso como este, cómo actuarías, ¿qué piensas, crees que lo correcto es ________? Se me ocurren muchas preguntas de este estilo.</p>\n\n\n\n<p>Si es una persona activa en redes, y la pregunta tiene sentido, difícil será que no te conteste y abra un diálogo.</p>\n\n\n\n<p>Interactuar con tu público objetivo de esta manera te acerca una paso más a ellos</p>\n\n\n\n<p>A veces, divide es vencerás. No intentes abarcar el mundo entero con una acción, rómpela en parcelas.</p>\n\n\n\n<p>Por ejemplo, marca un área próxima a ti físicamente y “péinala”. La cercanía da confianza, así que seguramente lo tengas un pelín mejor para que te escuchen</p>\n\n\n\n<p>¿Tienes la suerte de hablar otros idiomas? ¿Tu zona es bilingüe? Aprovéchalo para diferenciarte.</p>\n\n\n\n<h3 class=\"wp-block-heading\"><strong>4- Usa Google Maps para identificar empresas o posibles leads.</strong></h3>\n\n\n\n<p>A veces, divide es vencerás. No intentes abarcar el mundo entero con una acción, rómpela en parcelas, por ejemplo geográficas.</p>\n\n\n\n<p>Esto ayuda a focalizar tus esfuerzos en un objetivo, sobre todo si utilizas un evento local como excusa para contactar.</p>\n\n\n\n<p>La cercanía da confianza, así que seguramente lo tengas un pelín mejor para que te escuchen.</p>\n\n\n\n<p>¿Tienes la suerte de hablar otros idiomas? ¿Tu zona es bilingüe? Aprovéchalo para diferenciarte.</p>\n\n\n\n<p>Por ello, si tus clientes tienen algún tipo de negocio, considera el uso de Google Maps para prospectar por zonas. En ocasiones es la técnica más sencilla de obtener listados de profesionales.</p>\n\n\n\n<h3 class=\"wp-block-heading\"><strong>5- Si participas activamente en WordCamps, Meetups, etc. sácale partido</strong></h3>\n\n\n\n<p>Ya que estamos en WordPress ¿vas a participar en una WordCamp o Meetup? Intenta tomar parte activa de estos eventos. Patrocina, da una ponencia o preséntate como voluntario/a.</p>\n\n\n\n<p>Si das una ponencia o patrocinas un evento WordCamp o en una Meetup, <strong>localiza y envía un mensaje a posibles leads </strong>invitándolos a asistir (aquí te puede venir bien Google Maps de nuevo)</p>\n\n\n\n<p>Para esto, las Meetups son mejores que las WordCamps, ya que son locales y gratuitas, y en mi opinión, tienen más fuerza.</p>\n\n\n\n<p>Si tu charla es interesante y asisten a verte, no desaproveches la oportunidad de hablar personalmente con ellos/as.</p>\n\n\n\n<p>Prepara un “lead magnet” (un pequeño recurso online, PDF, etc.) para compartir con los asistentes. Eso te ayudará a tener una excusa para un contacto posterior y afianzar así tu red de contactos y networking. Para ello, no dudes en pedir sus credenciales si has estado hablando con ellos o búscalos proactivamente.</p>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>6- Prospecta en LinkedIn con automatizaciones</strong></h2>\n\n\n\n<p>Hay herramientas de automatización para LinkedIn que pueden sorprenderte. Algunas tienen una versión gratuita funcional, aunque limitada en potencia, pero suficiente para  principiantes.</p>\n\n\n\n<p>Hay funciones tan golosas como la importación de contactos por título laboral, sectores, ubicaciones, etc., que luego puedes utilizar para campañas de envío de mensajes, conectar, seguir, etc. O llevártelos a una hoja de cálculo para una prospección más manual.</p>\n\n\n\n<p>Puedes importarte, por ejemplo, los contactos de alguien de tu competencia…oops!</p>\n\n\n\n<p>PERO si utilizas alguna de estas herramientas, hazlo de manera «elegante” o quedarás fatal: </p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>No spamees, filtra y refiltra y apunta bien. </li>\n\n\n\n<li>Empieza ofreciendo una propuesta de valor desinteresada, real y relevante para la persona que la recibe. </li>\n\n\n\n<li>Respeto por delante. Contesta a quien te conteste.</li>\n</ul>\n\n\n\n<p>A tus leads les gusta el networking como a ti, la venta es todo el proceso, no únicamente la oferta final.</p>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>7- Plataformas de networking, bienvenidas.</strong></h2>\n\n\n\n<h3 class=\"wp-block-heading\">Conecta con tu entorno cercano. La proximidad geográfica genera confianza.</h3>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Date de alta en alguna plataforma de networking de tu zona.</li>\n\n\n\n<li>Visita a empresas o profesionales de tu zona, asiste a eventos locales, crea relaciones a largo plazo.</li>\n\n\n\n<li>Queda para tomar un café con personas de la zona, workshops presenciales, encuentros de networking locales, etc.</li>\n</ul>\n\n\n\n<p>Prospectar requiere de mucho tiempo que muy a menudo cae en saco roto, o eso nos parece. Valora las acciones en función del tiempo disponible que tienes, pero ten en cuenta que todo SUMA.</p>\n\n\n\n<p>Hay plataformas de networking virtuales como SinOficina que también son muy válidas. Hay que trabajar mucho el no poder tener presencia física y también requieren de tiempo. Mi consejo es que la pruebes igualmente</p>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>8. Visita a tus mejores clientes y mantén un contacto personal</strong></h2>\n\n\n\n<p>No te olvides de que quien ya te ha comprado sigue siendo tu objetivo, bien para fidelizarlo,&nbsp; bien para que te compre más servicios o productos.</p>\n\n\n\n<p>Para ello tienes que llamar a su timbre de vez en cuando y recordarles que estás presente.&nbsp;</p>\n\n\n\n<p>Recuerda escuchar y llevar pensadas preguntas que harán de tu visita algo valioso para ti. Para ello, te recomiendo seguir a<strong> Rosa Cools</strong>, experta en comunicación estratégica. Con ella vas a tener acceso a muchos recursos para usar la comunicación con tus clientes de manera efectiva y con intención…</p>\n\n\n\n<p>Si estás físicamente cerca, pásate a saludar, tomar un café o invitarlos a comer. Cuántas veces resulta que aparece una venta cuando te ven.&nbsp;</p>\n\n\n\n<p>Si estás más lejos, envíales algo en fechas señaladas. Una postal real en Navidad puede ser muy bienvenida (con mensaje personalizado). Utiliza otras festividades de una zona concreta para enviar una felicitación.&nbsp;</p>\n\n\n\n<p>O quizás podrías ofrecerles una auditoría gratuita de vez en cuando.</p>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>9- Pide reseñas de manera regular</strong></h2>\n\n\n\n<p>Que no te dé corte, a veces hay que dar un empujoncito a tus clientes para que te pongan una reseña. Son básicas para generar confianza.</p>\n\n\n\n<p>Por supuesto, úsalas en tu beneficio siempre que puedas. Llévalas a los feeds de las RRSS de tus leads.</p>\n\n\n\n<p>Para solicitarlas, puedes automatizar emails de seguimiento, integrar formularios de valoración en tu WordPress, etc. o aprovechar un encuentro.&nbsp;</p>\n\n\n\n<p>Cuánto más auténtica la petición, mejores resultados. No te desanimes, a la gente le cuesta horrores dejar una reseña.</p>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>10- Prepara tu web para recibir visitas</strong></h2>\n\n\n\n<p>Asegúrate de que tu sitio sea fácil y rápido de navegar y que no tenga errores (enlaces rotos, imágenes que faltan, errores gramaticales, etc.).</p>\n\n\n\n<p>Una buena herramienta para verificar que todo está ok en tu web es la versión gratuita de Ahrefs: te permite hacer auditorías de tu site para descubrir errores de enlazado interno y externo, páginas que no se indexan, 404s, etc. Otras funciones de Ahrefs están sólo en la versión de pago, pero encuentro que el “site audit” es suficientemente bueno.</p>\n\n\n\n<p>Otras herramientas que te pueden ir bien: Broken Link Checker, Google Search Console o PageSpeed Insights.</p>\n\n\n\n<p><br>No dejes que un 404 arruine tu trabajo de venta. La impresión que dé tu web puede ser decisiva para cerrar una venta.&nbsp;</p>\n\n\n\n<p>Cuántas veces he descartado a un profesional web como opción de contacto porque justamente su web era desastrosa, o directamente inexistente.&nbsp;</p>\n\n\n\n<h3 class=\"wp-block-heading\"><strong>Tips extra</strong></h3>\n\n\n\n<p>Una vez lances una acción de venta, prepara tu mente para lidiar con gente que se resista a comprarte.</p>\n\n\n\n<p>Uno de los argumentos de los que cuesta más defenderse es cuando te dicen que tu servicio o producto es caro. Lo que te están diciendo es que hay otras opciones con un precio más bajo.</p>\n\n\n\n<p>Actuamos por comparación.</p>\n\n\n\n<p>Por ello, ten en cuenta siempre la diferencia entre <strong>precio y valor.</strong></p>\n\n\n\n<p>Luchar a precio es una batalla perdida: quien te llega porque rebajas el precio por debajo de tus condiciones mínimas aceptables, se te irá por la misma razón.&nbsp;</p>\n\n\n\n<p>Cuando te compran por valor, el precio es secundario.</p>\n\n\n\n<p>Debes valorar tu servicio/producto en función de lo que realmente aporta. Esto refuerza tu reputación y evita a los que lo quieren todo gratis y si estás empezando, con más razón aún.<br>Lo caro y lo valioso son dos conceptos que no siempre van de la mano</p>\n\n\n\n<p>Sé la primera persona en creer en lo que vendes: La <strong>autoconfianza</strong> es clave para transmitir autoridad.</p>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>Pasa la Acción</strong></h2>\n\n\n\n<p>Llega la parte más dura, pasar a la acción.</p>\n\n\n\n<p>¿Miedo a que te rechacen? Míralo así: si no te equivocas o te dicen que no de vez en cuando, es que no estás haciendo suficiente.&nbsp;</p>\n\n\n\n<p>Todos nos hemos equivocado, hemos pasado la línea o simplemente nos han dicho que no de malas maneras.<br>Tu mejor antídoto es <strong>seguir intentándolo,</strong> porque el subidón cuando funciona es total.</p>\n\n\n\n<p>No hace falta que lo hagas todo a la vez.&nbsp;</p>\n\n\n\n<p>Escoge y cambia para no “quemarte”. Pero no olvides lo más importante en una venta:</p>\n\n\n\n<h3 class=\"wp-block-heading\"><strong>LA&nbsp; PERSEVERANCIA</strong></h3>\n\n\n\n<p>Sin ella, no llegarás lejos. Cuando escojas una línea de prospección, llévala hasta el final. Parar y arrancar, la intermitencia, es tu enemigo.</p>\n\n\n\n<p>Así que te dejo 3 sencillos pasos para empezar:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Revisa tus perfiles sociales para comprobar que muestras lo que tus leads querrán ver.</li>\n\n\n\n<li>Escoge uno de los trucos y ponlo en marcha ya…</li>\n\n\n\n<li>Bloquea un tiempo diario para prospectar. Por ejemplo: de 10 a 11h cada día. La rutina hará que sea más fácil ponerte.</li>\n\n\n\n<li>Ayúdate de la IA para redactar, pero no dejes que tome el control de tu discurso. Sé tú mismo/a.</li>\n\n\n\n<li>Llama para ver qué pasó con ese email que enviaste hace 2 días (no 2 semanas). Pocas veces me he encontrado con que no me respondan a esa pregunta. Es lo más rápido para obtener una respuesta honesta a tu oferta.</li>\n</ul>\n\n\n\n<p>No desistas, primero hay que sembrar para recoger. Date tiempo, pero no pares. Cada día un paso.</p>\n\n\n\n<p>Cuéntame en los comentarios o en redes sociales cómo te va.</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:95:\"https://es.wordpress.org/2025/07/10/10-trucos-para-potenciar-tus-ventas-de-forma-organica/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:6:\"693919\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:3;a:6:{s:4:\"data\";s:76:\"\n		\n		\n					\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:56:\"Tras la WC Málaga 2025: Reflexiones humanas sobre la IA\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:91:\"https://es.wordpress.org/2025/06/30/tras-la-wc-malaga-2025-reflexiones-humanas-sobre-la-ia/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:99:\"https://es.wordpress.org/2025/06/30/tras-la-wc-malaga-2025-reflexiones-humanas-sobre-la-ia/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 30 Jun 2025 07:58:43 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:9:\"Comunidad\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:8:\"WordCamp\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://es.wordpress.org/?p=693913\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:77:\"La IA y el valor del factor humano: inspiración desde la WordCamp de Málaga\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:15:\"Foteini Sofouri\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:8994:\"\n<p>Desde que la IA generativa se popularizó, debo admitir que mi postura ha sido <strong>más crítica que entusiasta</strong>. No por la tecnología en sí, sino por algunos usos que, de repente, empezaron a rodearme.</p>\n\n\n\n<p>Por un lado, los chatbots de atención al cliente que crean más frustración que soluciones, o posts en redes sociales que carecen de originalidad y emoción. Por otro lado, el impacto medio-ambiental que tienen estos usos y las consideraciones éticas que inevitablemente surgen.</p>\n\n\n\n<p>Sin embargo, no se puede ignorar lo obvio: la transformación enorme que está llevando a cabo, <strong>las oportunidades y la facilidad que puede generar su uso</strong>. Entonces, las preguntas que me surgen son: ¿cuáles son las cualidades humanas que la IA generativa no puede replicar? ¿Cuáles son los usos que podrían tener un beneficio común social? ¿Cómo podría el uso la IA facilitar mi trabajo personal sin sacrificar la calidad?</p>\n\n\n\n<p>Asistir a la WordCamp de Málaga me dio la oportunidad de reflexionar sobre estas cuestiones, responder algunas y generar nuevas. Sobre todo, he recopilado muchos aprendizajes sobre la IA que he podido aplicar a mi trabajo justo a la vuelta a casa (después del apagón que afectó España, claro).&nbsp;&nbsp;</p>\n\n\n\n<figure class=\"wp-block-embed is-type-photo is-provider-flickr wp-block-embed-flickr\"><div class=\"wp-block-embed__wrapper\">\n<a href=\"https://www.flickr.com/photos/wordpressphotos/54479882042/in/album-72177720325617873\"><img fetchpriority=\"high\" decoding=\"async\" src=\"https://live.staticflickr.com/65535/54479882042_94abea9eff.jpg\" alt=\"Roberto Vázquez\" width=\"500\" height=\"333\" /></a>\n</div><figcaption class=\"wp-element-caption\">Roberto Vázquez | WordCamp Málaga 2025 | Sábado| Delia Carballo: Charla de bienvenida</figcaption></figure>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>¿Puede la IA hacernos reír y conectar?</strong></h2>\n\n\n\n<p>Las charlas con las que se inauguró la WordCamp ofrecieron respuestas prácticas a esta pregunta y subrayaron el potencial de la IA generativa en la presencia digital.</p>\n\n\n\n<p>En la charla de Paula Carmona y Vanessa Martinez vimos cómo el contexto que proporcionamos en la IA puede ayudar a producir campañas enteras alineadas con la identidad de una marca. Recomendaron herramientas que se pueden combinar con la IA para ahorrar tiempo a la hora de crear una primera versión de una página web.</p>\n\n\n\n<p>Luego, Lidia Marbán nos demostró que al contrario de lo que mucha gente piensa, la IA puede hacernos reír y puede generar emociones que impulsen las ventas de una tienda online.</p>\n\n\n\n<p>A la vez, Luis Rodríguez Vives impartió un taller con ejemplos prácticos sobre cómo utilizar la IA generativa para la automatización, optimización y creación de contenido para tu público objetivo que puede posicionar y aumentar tus ventas.</p>\n\n\n\n<p>Así empezó la WordCamp de Málaga, con aprendizajes valiosos sobre cómo la IA puede ayudarnos a potenciar la presencia digital, marcando el tono para el resto del evento.</p>\n\n\n\n<p>Durante todo el día <strong>hubo charlas para varios niveles</strong>, con profesionales compartiendo experiencias reales y conocimientos de alto valor.</p>\n\n\n\n<h3 class=\"wp-block-heading\"><strong>¿Te perdiste la WordCamp? Aún puedes ponerte al día</strong></h3>\n\n\n\n<p>Todas las charlas están disponibles en WordPress TV así que, si te ha entrado “fomo”, puedes verlas ahí. (Yo ya he visto algunas en repeat para tomar más apuntes.)</p>\n\n\n\n<p>Lo que es más difícil reproducir online es la sensación de comunidad y compañerismo que está presente en las WordCamps.</p>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>Lo que la IA no puede replicar: Empatía, Comunidad y Diversidad</strong></h2>\n\n\n\n<p>Soy nueva en la comunidad WordPress, y lo que me encantó de la comunidad es que muchas personas que llevan más tiempo demuestran compañerismo, empatía y voluntad para ayudar y apoyar a personas que están empezando como yo. Desde ofrecer consejos y herramientas hasta charlas técnicas y profundas, hacen más fácil de lo que esperaba asistir estos eventos.</p>\n\n\n\n<h3 class=\"wp-block-heading\"><strong>Diversidad como una realidad que necesitamos visualizar</strong></h3>\n\n\n\n<p>Me alegró <strong>participar en una mesa sobre la diversidad durante el Contributor Day</strong>. Hablamos sobre cómo expandir la comunidad WordPress y cómo mejorar la inclusión en las WordCamps. Empaticé con problemáticas que se mencionaron y las palabras de las compañeras me hicieron reflexionar.</p>\n\n\n\n<p>Entendí, por ejemplo, lo imprescindible que es tener ludotecas en los eventos, ya que en caso contrario muchas personas, sobre todo mujeres, se excluyen.</p>\n\n\n\n<p>Se agradece que haya personas que intentan visibilizar estos temas, y me alegra que, según he percibido, la comunidad tiene la voluntad de escuchar y transformarse para mejorar la inclusión. Todavía hay mucho camino por delante, pero lo mencionado me genera optimismo.</p>\n\n\n\n<p>La diversidad es una realidad, hay tantas variaciones entre cómo funcionamos y percibimos el mundo que la IA difícilmente puede replicar. Por eso creo que no debemos ignorar esta realidad, pero visibilizarla sin perder de vista lo que nos une, creando una comunidad viva e inquieta.</p>\n\n\n\n<figure class=\"wp-block-embed is-type-photo is-provider-flickr wp-block-embed-flickr\"><div class=\"wp-block-embed__wrapper\">\n<a href=\"https://www.flickr.com/photos/wordpressphotos/54492124151/in/album-72177720325617873\"><img decoding=\"async\" src=\"https://live.staticflickr.com/65535/54492124151_76cc2ddac3.jpg\" alt=\"Koke Pérez\" width=\"500\" height=\"333\" /></a>\n</div><figcaption class=\"wp-element-caption\">Koke Pérez | WordCamp Málaga 2025 | Contributor Day</figcaption></figure>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>Reflexiones sobre la IA: oportunidades y desafíos</strong></h2>\n\n\n\n<p>El debate final sobre la IA representó varias de las reflexiones, a veces contradictorias que también comparto con los ponentes sobre la IA. La cuestión principal fue “¿Nos va a mandar a todos al paro la IA?”, y no tiene una respuesta sencilla.</p>\n\n\n\n<p>Nadie puede negar que nos facilita la vida con muchas tareas para las que antes necesitaríamos días, y sobre todo en los que trabajamos en el mundo digital se está convirtiendo en una herramienta potente.</p>\n\n\n\n<p>Pero no podemos olvidarnos de cuestiones éticas como las que se mencionaron en el debate: no hay igualdad en el acceso a ella y habrá personas cuyos puestos de trabajo desaparecerán de forma brusca.</p>\n\n\n\n<p>Es inevitable, pero como sociedad nos tocará solucionar estos problemas que pueden surgir y tenemos que pensar cómo organizarnos para apaliar las consecuencias negativas de la revolución de la IA, y <strong>orientar su evolución hacia usos que benefician a la humanidad</strong>.</p>\n\n\n\n<figure class=\"wp-block-embed is-type-photo is-provider-flickr wp-block-embed-flickr\"><div class=\"wp-block-embed__wrapper\">\n<a href=\"https://www.flickr.com/photos/wordpressphotos/54492391093/in/album-72177720325617873\"><img decoding=\"async\" src=\"https://live.staticflickr.com/65535/54492391093_296acb429a.jpg\" alt=\"Koke Pérez\" width=\"500\" height=\"333\" /></a>\n</div><figcaption class=\"wp-element-caption\">Koke Pérez | WordCamp Málaga 2025 | Sábado | Debate Final</figcaption></figure>\n\n\n\n<h3 class=\"wp-block-heading\"><strong>La formación como solución a los cambios bruscos</strong></h3>\n\n\n\n<p>Nos podemos hacer una idea, pero predecir lo que pasará es difícil, incluso si hablamos de los próximos 5 años.</p>\n\n\n\n<p>Lo seguro es que como profesionales nos tendremos que adaptar, lo cual reafirma la importancia que tiene la formación en estas nuevas habilidades, para facilitar esta transformación. </p>\n\n\n\n<p>Comunidades y eventos como las WordCamp se suman a este esfuerzo colectivo. </p>\n\n\n\n<p>Personalmente, salí de la WordCamp Málaga con una lista increíble de nuevas herramientas para probar, y también con ideas sobre casos de la aplicación de la IA en mi trabajo.</p>\n\n\n\n<h3 class=\"wp-block-heading\"><strong>Una visión humana y humanista en este nuevo escenario</strong></h3>\n\n\n\n<p>Lo que nos conecta con el presente, con la propia vida y con nuestra humanidad es colaborar, ayudar, compartir experiencias y crecer en comunidad. Mantener la inquietud y la creatividad, cuestionar y <strong>apostar por el esfuerzo y beneficio colectivo</strong>.</p>\n\n\n\n<figure class=\"wp-block-embed is-type-photo is-provider-flickr wp-block-embed-flickr\"><div class=\"wp-block-embed__wrapper\">\n<a href=\"https://www.flickr.com/photos/wordpressphotos/54480929794/in/album-72177720325617873\"><img loading=\"lazy\" decoding=\"async\" src=\"https://live.staticflickr.com/65535/54480929794_eaa6051b30.jpg\" alt=\"Nilo Vélez\" width=\"500\" height=\"333\" /></a>\n</div><figcaption class=\"wp-element-caption\">Nilo Vélez | WordCamp Málaga 2025  | Sábado | Voluntarios</figcaption></figure>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:96:\"https://es.wordpress.org/2025/06/30/tras-la-wc-malaga-2025-reflexiones-humanas-sobre-la-ia/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:6:\"693913\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:4;a:6:{s:4:\"data\";s:76:\"\n		\n		\n					\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:46:\"WordCamp Europe 2025: Basilea… Twelve points\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:79:\"https://es.wordpress.org/2025/06/06/wordcamp-europe-2025-basilea-twelve-points/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:87:\"https://es.wordpress.org/2025/06/06/wordcamp-europe-2025-basilea-twelve-points/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 06 Jun 2025 06:16:55 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:9:\"Comunidad\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:8:\"WordCamp\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://es.wordpress.org/?p=690328\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:126:\"WordCamp Europe 2025 aterriza en Basilea del 5 al 7 de junio. Comunidad, charlas, networking… ¡y Matt Mullenweg en directo!\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:10:\"lualvarimp\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:7016:\"\n<p>Sí, has leído bien… Doce puntazos que acaba de dar Kurrupekistán a través del voto telefónico al tema “<em>Un plugin valiente, poderoso</em>”…</p>\n\n\n\n<p>Y es que este tipo de situaciones sólo se pueden vivir en el evento WordPress más grande de toda Europa: <strong>WordCamp Europe 2025</strong>, que este año se hará <strong>en el Messe Basel and Congress Center, en la ciudad de Basilea, Suiza, los días 5 al 7 de junio</strong>.</p>\n\n\n\n<p>Y este año también se va a liar una buena, al igual que ocurrió en la edición anterior de Turín, porque una horda de más de 2500 enfervorizados WordPressFans va a invadir la ciudad, haciendo que los suizos se planteen cerrar sus fronteras por segunda vez en menos de un mes (como si no hubieran tenido suficiente con el festival europeo de la canción).</p>\n\n\n\n<p><a href=\"https://europe.wordcamp.org/2025/tickets/\" target=\"_blank\" rel=\"noreferrer noopener\">Comprar entrada</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">Las comparaciones son odiosas… Pero son inevitables…&nbsp;</h2>\n\n\n\n<p>Sé que has llegado hasta aquí buscando <strong>contenido de calidad</strong> y que al final vas a acabar leyendo mis tonterías… Pero es lo que hay, así que vamos a pasar un buen rato tú y yo con estas rarezas.</p>\n\n\n\n<p>¿Sabías que tanto en el festival europeo de la canción como en las WordCamps la gente va por ahí con su acreditación colgando del cuello?&#8230; Y en ellas pone su nombre y a qué se dedican (y lo pasan bastante mal si en ellas se puede leer “el que hace los coros a la diva” o “recién llegado a WordPress”)</p>\n\n\n\n<p>¿Y las sonrisas?&#8230; Están presentes por doquier… Enseñas la dentadura a todo el mundo mientras haces un gesto amistoso o sacudes levemente la cabeza… Y todo el mundo te devuelve el gesto y te enseña su dentadura… Creo que algún jefazo debería plantearse tener como patrocinador de estos eventos a cualquier empresa que vendiese pasta dentífrica.</p>\n\n\n\n<p>¿Y los regalitos?&#8230; ¡Dios mío! … En el festival de la canción los asistentes lucen sus pulseras de color fosforito, brillando en la oscuridad, unas diademas con luces led que te dejan ciego y toneladas de brillantina pegada a la ropa, que seguro revienta la lavadora si la echas a lavar…</p>\n\n\n\n<p>En la WordCamp pasa algo parecido (o incluso mejor): haces acopio de tazas, pegatinas, pines, bolígrafos y algún que otro gadget que le va a venir genial a tu portátil. Hay veces que incluso consigues unos calcetines de estrambóticos colores que, si los llevas puestos, dirán mucho a tus colegas de profesión, pero harán huir despavorida a quien no quieres como pareja.</p>\n\n\n\n<p><a href=\"https://europe.wordcamp.org/2025/tickets/\" target=\"_blank\" rel=\"noreferrer noopener\">Comprar entrada</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">La unión hace la fuerza (o eso dicen)</h2>\n\n\n\n<p>¿Te imaginas que se fusionaran ambos eventos en uno sólo?&#8230; Eurovision Song Contest + WordCamp Europe&#8230; ¿Cómo sería?&#8230; ¿El WordPress Speaker Contest?&#8230; Yo ya lo estoy viendo en mi cabeza:</p>\n\n\n\n<p>“Y representando a España, la ponencia <em>Gutenberg My Love</em>,</p>\n\n\n\n<p>interpretada por Pepito Castracuejo.”</p>\n\n\n\n<p>Y entonces comienza la ponencia, se apagan las luces y del techo desciende una luna hinchable sobre la que va montado un hombre con capa y disfrazado de plátano maduro que, a gritos de Death Metal, te recita en verso las virtudes del editor de bloques nativo de WordPress.</p>\n\n\n\n<p>¿No te parece que sería algo digno de ver? (al menos por lo original y diferente de cualquier otra propuesta tradicional).</p>\n\n\n\n<p><a href=\"https://europe.wordcamp.org/2025/tickets/\" target=\"_blank\" rel=\"noreferrer noopener\">Comprar entrada</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">Una WordCamp que promete ser una revolución</h2>\n\n\n\n<p>Bueno… Ya sabes de sobra que este tipo de cosas no van a ocurrir en la <strong>Wordcamp Europe 2025 de Basilea</strong>, que tendrá lugar en Suiza, <strong>en el Messe Basel and Congress Center, los días 5 al 7 de junio</strong>.</p>\n\n\n\n<p>Lo que sí que sabes es que, como toda WordCamp internacional que se precie, <strong>el listón va a estar muy alto</strong> con unas <strong>ponencias increíbles</strong>, un ambientazo de los que quitarse el sombrero y un <strong>networking de los buenos</strong>, de esos que, si pones interés por tu parte, sales de allí con un trabajo bajo el brazo.</p>\n\n\n\n<p>Y eso que no te hablo del After Party… ¡El mítico After Party de la WordCamp Europe!&#8230; Eso sí que es una fiesta y lo demás son tonterías.</p>\n\n\n\n<p><a href=\"https://europe.wordcamp.org/2025/tickets/\" target=\"_blank\" rel=\"noreferrer noopener\">Comprar entrada</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">Matt is on the track!</h2>\n\n\n\n<p>Matt is on the track!&#8230; Matt is on the track!!!</p>\n\n\n\n<p>¡Así como lo lees! El 7 de junio (qué día más bonito, felicítame por mi cumpleaños&#8230;), <strong>Matt Mullenweg estará en la WordCamp</strong> dando una charla informal junto a Mary Hubbard.</p>\n\n\n\n<p>¡Matt Mullenweg, el creador de WordPress!!! (Me tiro de los pelos entre efusividad y estrés).</p>\n\n\n\n<p>¿Necesitas algún otro motivo para ir a la <strong>WordCamp Europe 2025 de Basilea</strong>?&#8230; Estoy convencido de que te acabas de emocionar tanto como yo y de que se te ocurrirán un montón de buenas preguntas para hacerle al bueno de Matt.</p>\n\n\n\n<p>Bueno, las preguntas inteligentes se te ocurrirán a ti, porque lo que es a mí… ¡No!… Definitivamente mi cerebro sería incapaz de formular una pregunta con el más mínimo interés.</p>\n\n\n\n<p>Y hasta aquí llega este escrito, que de calidad tiene poco, pero que de <strong>pasión por entretenerte</strong> tiene un rato.</p>\n\n\n\n<p><a href=\"https://europe.wordcamp.org/2025/tickets/\" target=\"_blank\" rel=\"noreferrer noopener\">Comprar entrada</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">Conclusión (como diría una IA)</h2>\n\n\n\n<p>Si puedes, pásate por la<strong> WordCamp Europe 2025 de Basilea, en el Messe Basel and Congress Center, los días 5 al 7 de junio</strong>.</p>\n\n\n\n<p>Pégate un viajecito hasta Suiza y disfruta de una WordCamp que promete informarte sobre <strong>lo último en tendencias</strong> y sobre lo nuevo que va a venir a WordPress… Una WordCamp de un <strong>nivel internacional alucinante</strong> en la que, a poco que te esfuerces, podrás hacer contactos con gente de todo el planeta e intercambiar conocimientos con ellos.</p>\n\n\n\n<p>Y no nos olvidemos de <strong>la fiesta y el networking</strong>, porque en la edición anterior fue una auténtica pasada y este año, Basilea no se va a quedar atrás (<strong>las oportunidades de trabajo y de negocio están ahí</strong>, sólo tienes que buscarlas y atraparlas).</p>\n\n\n\n<p>Disfruta de esta WordCamp Europe 2025.</p>\n\n\n\n<p><a href=\"https://europe.wordcamp.org/2025/tickets/\" target=\"_blank\" rel=\"noreferrer noopener\">Comprar entrada</a></p>\n\n\n\n<p>¡Nos vemos!</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:84:\"https://es.wordpress.org/2025/06/06/wordcamp-europe-2025-basilea-twelve-points/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:6:\"690328\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:5;a:6:{s:4:\"data\";s:76:\"\n		\n		\n					\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:61:\"Misterio en la WordCamp Logroño 2025: La cosecha del código\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:95:\"https://es.wordpress.org/2025/05/19/misterio-en-la-wordcamp-logrono-2025-la-cosecha-del-codigo/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:104:\"https://es.wordpress.org/2025/05/19/misterio-en-la-wordcamp-logrono-2025-la-cosecha-del-codigo/#comments\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 19 May 2025 19:06:45 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:9:\"Comunidad\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:8:\"WordCamp\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://es.wordpress.org/?p=689035\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:119:\"Un enólogo, una botella secreta y una WordCamp. ¿Qué puede salir mal? Descúbrelo el  23 y 24 de mayo. #WCLOGROÑO25\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:10:\"lualvarimp\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:9044:\"\n<p>¿Qué hacía un enólogo en un evento de WordPress? La respuesta se encontraba en una vieja leyenda, medio susurro y medio borrachera, que circulaba desde hacía eones por las bodegas de autor de la zona.</p>\n\n\n\n<p>Los pasos de Lewis Lonswar, enólogo de profesión y detective por necesidad, se dirigieron con decisión hacia el <strong>Centro de la Cultura del Rioja</strong>, un edificio imponente en el que tendría lugar la <strong>WordCamp Logroño 2025</strong>, durante el <strong>23 y 24 de mayo</strong>. La primera WordCamp que iban a celebrar en toda su historia.&nbsp;</p>\n\n\n\n<p><a href=\"https://logrono.wordcamp.org/2025/comprar-entradas/\">comprar entrada</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">Sospechoso, muy sospechoso</h2>\n\n\n\n<p>Una semana antes, un soplón se puso a cantar como un canario, confesando que, sólo durante esos dos días, una botella de valor incalculable, tan antigua como exquisita y tan secreta que ni los bots la podrían indexar, estaría oculta en aquel edificio municipal, en pleno corazón de la ciudad del vino.</p>\n\n\n\n<p>Una botella por la que muchos matarían.&nbsp;</p>\n\n\n\n<p>La curiosidad y el misterio despertaron en Lewis un apetito que ningún Ribera del Duero podría saciar. No podía dejar pasar la oportunidad de saborear ese misterio. “<strong>Cuando la vida te da uvas… Haces vino</strong>”, se dijo a sí mismo.</p>\n\n\n\n<p>El <strong>Centro de la Cultura del Rioja</strong> lucía espléndido aquella mañana. Un cartel en la entrada anunciaba con letras enormes el evento de la <strong>WordCamp Logroño 2025</strong> y debajo se podía leer la fecha <strong>del 23 al 24 de mayo</strong>.</p>\n\n\n\n<p>Nada más entrar, alguien de la organización le dio su acreditación y una mochila con regalos en su interior. Lewis sintió un pálpito en su corazón. En el ambiente se respiraba una extraña energía, mezcla de WiFi revolucionado y mosto fermentado. Además, todos los asistentes llevaban en sus ojos ese brillo que solo tienen quienes vienen a <strong>compartir conocimiento</strong>.</p>\n\n\n\n<p><a href=\"https://logrono.wordcamp.org/2025/comprar-entradas/\">comprar entrada</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">Algo estaba pasando</h2>\n\n\n\n<p>Empezó a moverse con libertad por el recinto, observando e investigando a <strong>los organizadores que orquestaban el evento con precisión suiza y alegría española</strong>, mientras <strong>los patrocinadores atraían con sus servicios a la gente</strong> que curioseaba y chispeaba como un vino joven.</p>\n\n\n\n<p>Pero Lewis no pensaba desviarse de su misión. Encontraría aquella botella añeja, aunque tuviera que bucear entre <strong>plugins y networking</strong>.</p>\n\n\n\n<p>Fue en un momento de descuido cuando algo le golpeó por la espalda. <strong>Una ponencia brillante</strong> estuvo a punto de hacerle caer, pero se repuso y la enfrentó sin miedo. Pero <strong>aquel discurso era tan magistral y estaba tan bien estructurado</strong> que Lewis no pudo hacer nada y, tras acabar la intervención del ponente, se derrumbó sobre una silla, perdiendo el conocimiento.</p>\n\n\n\n<p>Antes de que sus ojos se sumieran en la negrura, escuchó en la lejanía una voz que le susurró al oído: “<em>El código está en el código</em>”.</p>\n\n\n\n<p><a href=\"https://logrono.wordcamp.org/2025/comprar-entradas/\">comprar entrada</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">¿El qué en el qué?</h2>\n\n\n\n<p>No sabría decir cuánto tiempo pasó antes de volver en sí. La cabeza le zumbaba. Aquella frase se había transformado en una letanía que se repetía en sus pensamientos una y otra vez, como si con ello, su cerebro pudiera encontrar una respuesta. No lo consiguió.&nbsp;</p>\n\n\n\n<p>“<em>A veces, solo el código sabe lo que pasa</em>”.</p>\n\n\n\n<p>Su instinto se impuso a la cordura y Lewis <strong>acudió a todas las ponencias</strong> de comunicación, de maquetación, de interacción, Woocommerce, chatbots, CSS… <strong>Todas eran geniales. Todas eran oro puro</strong>.</p>\n\n\n\n<p>Pero las que más le llamaron la atención fueron las de SEO. En ellas aprendió que hasta el vino más excelente necesita de una buena etiqueta para ser encontrado.</p>\n\n\n\n<p>¡Ahí radicaba la solución al misterio que lo había llevado hasta aquel lugar!</p>\n\n\n\n<p><a href=\"https://logrono.wordcamp.org/2025/comprar-entradas/\">comprar entrada</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">Sigue las migas de pan</h2>\n\n\n\n<p>Aprovechando los aplausos de los asistentes ante <strong>otra ponencia espectacular</strong>, se escabulló, infiltrándose entre bastidores con la astucia de un zorro y la discreción de una copa servida sin ruido. Empezó a buscar pistas, señales y etiquetas.</p>\n\n\n\n<p>Se guió por la lógica del código como quien sigue el aroma de una fermentación espontánea y, al poco, tras un panel decorativo, encontró un acceso oculto, protegido por un puzle a modo de cerradura.</p>\n\n\n\n<p>Parecía abrirse con una combinación compleja de <strong>bloques de Gutenberg</strong>, pero aquel puzzle resultaba demasiado evidente. Recordó entonces todas las charlas a las que acudió y el momento en el que entró al recinto… Y entonces, en su mente, se formó la solución al acertijo.</p>\n\n\n\n<p>Siempre había estado ahí mismo, delante de sus narices, escondida en el cartel que anunciaba que la <strong>WordCamp Logroño 2025</strong> se celebraría en el <strong>Centro de la Cultura del Rioja</strong> durante el <strong>23 y 24 de mayo</strong>.</p>\n\n\n\n<p>Tras introducir la clave, una puerta se abrió.</p>\n\n\n\n<p><a href=\"https://logrono.wordcamp.org/2025/comprar-entradas/\">comprar entrada</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">El Quiz revelado</h2>\n\n\n\n<p>El cuarto estaba en penumbra. Iluminación tenue. Humedad controlada. En el aire flotaba un suave aroma a roble viejo que no podía ocultar el hedor al secretismo. Al fondo de la sala, sobre un pedestal, descansaba la botella legendaria: sin etiqueta, sin nombre, solo un pequeño símbolo grabado en el vidrio… El logo de WordPress.</p>\n\n\n\n<p>Lewis la tomó entre sus manos con reverencia. Era real. No un mito, no una metáfora: La cosecha del código.</p>\n\n\n\n<p>Pero justo entonces, escuchó unas risas al otro lado del panel. <strong>Una charla acabó y la gente comenzó a salir entusiasmada, comentando ideas, compartiendo proyectos, conectando</strong>.</p>\n\n\n\n<p>Comprendió entonces que la <strong>comunidad WordPress</strong> no era solo código o tener más conocimientos o poder que tu contrario. <strong>WordPress era pasión, colaboración, creatividad</strong>. <strong>Gente que imaginaba, compartía, enseñaba y aprendía</strong> con la misma alegría con la que él solía brindar con una copa de vino en su bodega favorita.</p>\n\n\n\n<p>Se quedó mirando la botella. Allí estaba, perfecta. Pero por primera vez, no sintió la necesidad de abrirla y degustar su contenido.</p>\n\n\n\n<p>Allí sólo, sin compañía, no merecía la pena.</p>\n\n\n\n<p>La devolvió a su pedestal y cerró tras de sí, dejando el panel secreto tal y como se lo encontró.</p>\n\n\n\n<p><a href=\"https://logrono.wordcamp.org/2025/comprar-entradas/\">comprar entrada</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">Comunidad</h2>\n\n\n\n<p>Volvió a la sala principal, donde le ofrecieron un vaso de agua tras una <strong>jornada intensa de charlas y conocimientos</strong>.&nbsp; Lewis brindó con <strong>aquellos desconocidos que ya eran colegas</strong>. Empezó a reírse a carcajadas junto a los <strong>organizadores que se desvivieron por cada detalle</strong>. Aprendió de los <strong>ponentes que hablaban con la misma pasión</strong> con la que un viticultor cuidaba su vendimia.</p>\n\n\n\n<p>Y entonces lo comprendió todo: <strong>la verdadera joya no era el vino oculto. Era la comunidad</strong>.</p>\n\n\n\n<p>La comunidad era el verdadero lugar donde la gente se ayudaba y se apoyaba, sin importar desencuentros anteriores. Un sitio donde las ideas fermentaban, maduraban y se compartían.</p>\n\n\n\n<p>Lo otro, era estar junto al vino más valioso del mundo, pero solo y abandonado.</p>\n\n\n\n<h2 class=\"wp-block-heading\">¿Fin?</h2>\n\n\n\n<p>¡Pues claro que esto no es el fin de la historia!&#8230; ¿O acaso no te ha servido de nada conocer la historia de Lewis Lonswar, el enólogo de profesión y detective por necesidad?</p>\n\n\n\n<p>No te lo puedo dejar más clarito, <strong>la WordCamp Logroño 2025 va a ser la caña</strong>. Tienen a unos ponentes espectaculares, el recinto, el <strong>Centro de la Cultura del Rioja</strong>, es alucinante y, además, es la primera WordCamp que organiza esta gente que tanta pasión ha puesto en el proyecto, así que las ilusiones puestas en esta WordCamp no podrían ser más altas.</p>\n\n\n\n<p>No te lo pienses mucho y <strong>reserva en tu agenda los días 23 y 24 de mayo</strong> porque, aunque no encuentres esa botella secreta, seguro que vas a descubrir algo mucho más valioso.</p>\n\n\n\n<p>¡Nos vemos en Logroño!</p>\n\n\n\n<p><a href=\"https://logrono.wordcamp.org/2025/comprar-entradas/\">comprar entrada</a></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:100:\"https://es.wordpress.org/2025/05/19/misterio-en-la-wordcamp-logrono-2025-la-cosecha-del-codigo/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"1\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:6:\"689035\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:6;a:6:{s:4:\"data\";s:82:\"\n		\n		\n					\n		\n		\n		\n				\n		\n		\n		\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:51:\"WordPress 6.8.1 – Actualización de mantenimiento\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:83:\"https://es.wordpress.org/2025/04/30/wordpress-6-8-1-actualizacion-de-mantenimiento/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:92:\"https://es.wordpress.org/2025/04/30/wordpress-6-8-1-actualizacion-de-mantenimiento/#comments\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 30 Apr 2025 18:58:01 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:4:{i:0;a:5:{s:4:\"data\";s:15:\"Actualizaciones\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:13:\"Mantenimiento\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:3:\"6.8\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:3;a:5:{s:4:\"data\";s:5:\"6.8.1\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://es.wordpress.org/?p=687674\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:342:\"Esta actualización menor incluye correcciones de 15 fallos en el núcleo y en el editor de bloques solucionando problemas que afectan a múltiples áreas de WordPress, incluidos el editor de bloques, multisitio y la API REST. Para ver la lista completa de correcciones a fallos echa un vistazo al anuncio de la versión candidata a [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:16:\"Fernando Tellado\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:7309:\"\n<p>Esta actualización menor incluye correcciones de 15 fallos <a href=\"https://core.trac.wordpress.org/query?resolution=fixed&amp;milestone=6.8.1&amp;group=component&amp;col=id&amp;col=summary&amp;col=milestone&amp;col=owner&amp;col=type&amp;col=status&amp;col=priority&amp;order=priority\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">en el núcleo</a> y en <a href=\"https://github.com/WordPress/wordpress-develop/pull/8752\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">el editor de bloques</a> solucionando problemas que afectan a múltiples áreas de WordPress, incluidos el editor de bloques, multisitio y la API REST. Para ver la lista completa de correcciones a fallos echa un vistazo al <a href=\"https://make.wordpress.org/core/2025/04/28/wordpress-6-8-1-rc1-is-now-available/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">anuncio de la versión candidata a definitiva.</a></p>\n\n\n\n<p>WordPress 6.8.1 es una actualización de mantenimiento de ciclo corto. Durante 2025 habrá disponibles más versiones de mantenimiento.</p>\n\n\n\n<p>Si tienes sitios que admitan las actualizaciones automáticas en segundo plano el proceso de actualización empezará automáticamente.</p>\n\n\n\n<p>Puedes <a href=\"https://es.wordpress.org/latest-es_ES.zip\" data-type=\"link\" data-id=\"https://es.wordpress.org/latest-es_ES.zip\" rel=\"nofollow\">descargar WordPress 6.8.1 desde WordPress.org</a>, o visitar el escritorio de tu WordPress, hacer clic en «Actualizaciones» y luego clic en «Actualizar ahora». Para más información sobre esta versión visita el <a href=\"https://wordpress.org/support/wordpress-version/version-6-8-1\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">centro de ayuda</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Gracias a estos contribuidores a WordPress</h2>\n\n\n\n<p>Esta versión la lideró <a href=\"https://profiles.wordpress.org/jorbin/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">Aaron Jorbin</a>.</p>\n\n\n\n<p>WordPress 6.8.1 no habría sido posible sin las contribuciones de las siguientes personas Su coordinación asíncrona a la hora de convertir correcciones de mantenimiento en una versión estable es un testamento del poder y capacidad de la comunidad WordPress.</p>\n\n\n\n<p><a href=\"https://profiles.wordpress.org/jorbin\">Aaron Jorbin</a>, <a href=\"https://profiles.wordpress.org/adamsilverstein\">Adam Silverstein</a>, <a href=\"https://profiles.wordpress.org/wildworks\">Aki Hamano</a>, <a href=\"https://profiles.wordpress.org/ankitmaru\">Ankit Panchal</a>, <a href=\"https://profiles.wordpress.org/bernhard-reiter\">bernhard-reiter</a>, <a href=\"https://profiles.wordpress.org/poena\">Carolina Nymark</a>, <a href=\"https://profiles.wordpress.org/codeamp\">Code Amp</a>, <a href=\"https://profiles.wordpress.org/talldanwp\">Daniel Richards</a>, <a href=\"https://profiles.wordpress.org/davidbaumwald\">David Baumwald</a>, <a href=\"https://profiles.wordpress.org/justlevine\">David Levine</a>, <a href=\"https://profiles.wordpress.org/dilipbheda\">Dilip Bheda</a>, <a href=\"https://profiles.wordpress.org/dd32\">Dion Hulse</a>, <a href=\"https://profiles.wordpress.org/dsawyers\">dsawyers</a>, <a href=\"https://profiles.wordpress.org/eduwass\">eduwass</a>, <a href=\"https://profiles.wordpress.org/ethitter\">Erick Hitter</a>, <a href=\"https://profiles.wordpress.org/estelaris/\">Estela Rueda</a>, <a href=\"https://profiles.wordpress.org/fabiankaegy\">Fabian Kägy</a>, <a href=\"https://profiles.wordpress.org/mamaduka\">George Mamadashvili</a>, <a href=\"https://profiles.wordpress.org/gziolo\">Greg Ziółkowski</a>, <a href=\"https://profiles.wordpress.org/kabir93\">H. Kabir</a>, <a href=\"https://profiles.wordpress.org/hideishi\">hideishi</a>, <a href=\"https://profiles.wordpress.org/abcd95\">Himanshu Pathak</a>, <a href=\"https://profiles.wordpress.org/jarekmorawski\">jarekmorawski</a>, <a href=\"https://profiles.wordpress.org/audrasjb\">Jb Audras</a>, <a href=\"https://profiles.wordpress.org/JeffPaul\">Jeffrey Paul</a>, <a href=\"https://profiles.wordpress.org/jeffr0\">Jeffro</a>, <a href=\"https://profiles.wordpress.org/jeremyfelt\">Jeremy Felt</a>, <a href=\"https://profiles.wordpress.org/joedolson\">Joe Dolson</a>, <a href=\"https://profiles.wordpress.org/joemcgill\">Joe McGill</a>, <a href=\"https://profiles.wordpress.org/joen\">Joen A.</a>, <a href=\"https://profiles.wordpress.org/johnjamesjacoby\">John James Jacoby</a>, <a href=\"https://profiles.wordpress.org/desrosj\">Jonathan Desrosiers</a>, <a href=\"https://profiles.wordpress.org/spacedmonkey\">Jonny Harris</a>, <a href=\"https://profiles.wordpress.org/verygoode\">Joshua Goode</a>, <a href=\"https://profiles.wordpress.org/karthikeya01\">Karthikeya Bethu</a>, <a href=\"https://profiles.wordpress.org/iamkingsleyf\">Kingsley Felix</a>, <a href=\"https://profiles.wordpress.org/obenland\">Konstantin Obenland</a>, <a href=\"https://profiles.wordpress.org/0mirka00\">Lena Morita</a>, <a href=\"https://profiles.wordpress.org/lilgames\">LilGames</a>, <a href=\"https://profiles.wordpress.org/megane9988\">megane9988</a>, <a href=\"https://profiles.wordpress.org/marktimemedia\">Michelle Schulp Hunt</a>, <a href=\"https://profiles.wordpress.org/presstoke\">Mitchell Austin</a>, <a href=\"https://profiles.wordpress.org/mukesh27\">Mukesh Panchal</a>, <a href=\"https://profiles.wordpress.org/nickwilmot\">nickwilmot</a>, <a href=\"https://profiles.wordpress.org/nikunj8866\">Nikunj Hatkar</a>, <a href=\"https://profiles.wordpress.org/swissspidy\">Pascal Birchler</a>, <a href=\"https://profiles.wordpress.org/pbiron\">Paul Biron</a>, <a href=\"https://profiles.wordpress.org/peterwilsoncc\">Peter Wilson</a>, <a href=\"https://profiles.wordpress.org/pratiklondhe\">Pratik Londhe</a>, <a href=\"https://profiles.wordpress.org/presskopp\">Presskopp</a>, <a href=\"https://profiles.wordpress.org/sainathpoojary\">Sainath Poojary</a>, <a href=\"https://profiles.wordpress.org/sc0ttkclark\">Scott Kingsley Clark</a>, <a href=\"https://profiles.wordpress.org/coffee2code/\">Scott Reilly</a>, <a href=\"https://profiles.wordpress.org/SergeyBiryukov\">Sergey Biryukov</a>, <a href=\"https://profiles.wordpress.org/SirLouen\">SirLouen</a>, <a href=\"https://profiles.wordpress.org/soean\">Sören Wünsch</a>, <a href=\"https://profiles.wordpress.org/sourav08\">Sourav Pahwa</a>, <a href=\"https://profiles.wordpress.org/sabernhardt\">Stephen Bernhardt</a>, <a href=\"https://profiles.wordpress.org/takuword\">takuword</a>, <a href=\"https://profiles.wordpress.org/tusharaddweb\">Tushar Patel</a>, <a href=\"https://profiles.wordpress.org/westonruter\">Weston Ruter</a>, <a href=\"https://profiles.wordpress.org/yogeshbhutkar\">Yogesh Bhutkar</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">Cómo contribuir</h2>\n\n\n\n<p>Para involucrarte en el desarrollo del núcleo de WordPress, pásate por el Trac, <a href=\"https://core.trac.wordpress.org/report/6\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">elige un ticket</a> y únete a la conversión en los canales <a href=\"https://wordpress.slack.com/archives/C02RQBWTW\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">#core</a> y <a href=\"https://wordpress.slack.com/archives/C080HLPP2Q6\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">#6-8-release-leads</a>. ¿Necesitas ayuda? Echa un vistazo al <a href=\"https://make.wordpress.org/core/handbook/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">manual del contribuidor al núcleo</a>.</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:88:\"https://es.wordpress.org/2025/04/30/wordpress-6-8-1-actualizacion-de-mantenimiento/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"1\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:6:\"687674\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:7;a:6:{s:4:\"data\";s:70:\"\n		\n		\n					\n		\n		\n		\n				\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:58:\"WordCamp Bilbao 2025: Que viene, que viene… ¡Eh, eh!…\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:83:\"https://es.wordpress.org/2025/04/29/wordcamp-bilbao-2025-que-viene-que-viene-eh-eh/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:91:\"https://es.wordpress.org/2025/04/29/wordcamp-bilbao-2025-que-viene-que-viene-eh-eh/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 29 Apr 2025 09:47:07 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://es.wordpress.org/?p=687666\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:337:\"¡Aúpa, familia WordPressera!&#8230; Como ves, aquí está toda la cuadrilla de Bilbao para darte la bienvenida a la WordCamp más épica que podrás vivir en décadas (bueno, en verdad sólo en un año, cuando volvamos a hacer la siguiente edición). Comprar entrada ¿Cómo no vas a venir a Bilbao? Iré al grano para que te [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:10:\"lualvarimp\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:7226:\"\n<p>¡Aúpa, familia WordPressera!&#8230;</p>\n\n\n\n<p>Como ves, aquí está toda la cuadrilla de Bilbao para darte la bienvenida a <strong>la WordCamp más épica</strong> que podrás vivir en décadas (bueno, en verdad sólo en un año, cuando volvamos a hacer la siguiente edición).</p>\n\n\n\n<p><a href=\"https://bilbao.wordcamp.org/2025/comprar-entrada/\" target=\"_blank\" rel=\"noreferrer noopener\">Comprar entrada</a> </p>\n\n\n\n<h2 class=\"wp-block-heading\">¿Cómo no vas a venir a Bilbao?</h2>\n\n\n\n<p>Iré al grano para que te centres en lo que de verdad importa, que es venir a <strong>la ciudad más impresionante del mundo</strong>. Sí, ya sé que piensas que la tuya es la que más te gusta. Hasta los neoyorquinos piensan eso de la suya pero, ¡aivalaostia!: eso es porque no has venido a Bilbao.&nbsp;</p>\n\n\n\n<p>En fin, que este año <strong>volvemos a hacer la WordCamp Bilbao en As Fabrik</strong>, así que ve dejando hueco en tu agenda para <strong>los días 10 y 11 de mayo</strong> y también deja otro hueco para tu estómago porque, este año, la mochila de bienvenida contendrá un tupper de marmitako, otro de txipirones en su tinta y, por último, un pequeño txuleton de kilo y medio para que empieces el día con energía.&nbsp;</p>\n\n\n\n<p>Así <strong>podrás escuchar las impresionantes charlas que darán los mejores ponentes</strong> que encontrarás al norte de la península (y también al sur, al este y al oeste) y que tratarán de temas tan interesante como: <strong>Local Services y WordPress, APIs, mejorar el SEO/SEM</strong>, etc…</p>\n\n\n\n<p><a href=\"https://bilbao.wordcamp.org/2025/comprar-entrada/\" target=\"_blank\" rel=\"noreferrer noopener\">Comprar entrada</a> </p>\n\n\n\n<h2 class=\"wp-block-heading\">¡Hora de la merendola!</h2>\n\n\n\n<p>Y como sé que cuando llegue el hamaiketako (a eso de las 11:00 horas) te estará rugiendo el estómago, pausaremos las charlas y te tendremos preparado un buen plato de bacalao al pil-pil para que no te nos desmayes en mitad del evento.&nbsp;</p>\n\n\n\n<p>Como entretenimiento mientras llenas el buche, podrás ver a Patxi, que amenizará la merienda levantando piedras de quinientos kilos con las pestañas (y poco me parece, pero es que el chaval está empezando en esto y aún no tiene experiencia).&nbsp;</p>\n\n\n\n<p>Tras haber tomado un poco de fuerza con el aperitivo, tendrás varias ponencias que tratarán sobre la <strong>comunidad WordPress, sobre colores, sobre escribir con IA, sobre Green Marketing</strong>, etc…</p>\n\n\n\n<p><a href=\"https://bilbao.wordcamp.org/2025/comprar-entrada/\" target=\"_blank\" rel=\"noreferrer noopener\">Comprar entrada</a> </p>\n\n\n\n<h2 class=\"wp-block-heading\">¡Sonríe, que te están enfocando!</h2>\n\n\n\n<p>¡Y entonces llegará el momento de <strong>la fotografía de grupo</strong>!&#8230; Pero no te preocupes, que saldrás hecho un pincel y con todo lujo de detalles en la foto junto a toda tu familia WordPressera.&nbsp;</p>\n\n\n\n<p>Ya hemos hablado con la NASA para que nos tomen la imagen con más resolución y más espectacular que jamás se haya hecho y hemos encargado el satélite más grande que tienen en el espacio (aunque, la verdad, Txomin tiene ovejas en su rebaño más grandes que esa máquina flotando en el exterior).&nbsp;</p>\n\n\n\n<p>¡Qué le vamos a hacer!&#8230; <strong>¡Así somos los de Bilbao!</strong> (sobre todo yo, que tengo el carnet de bilbaíno de pura cepa).</p>\n\n\n\n<p><a href=\"https://bilbao.wordcamp.org/2025/comprar-entrada/\" target=\"_blank\" rel=\"noreferrer noopener\">Comprar entrada</a> </p>\n\n\n\n<h2 class=\"wp-block-heading\">Banquete al estilo bilbaíno&nbsp;</h2>\n\n\n\n<p>Luego llegará el momento de la comida. ¿Recuerdas a los irreductibles galos de Goscinny y Uderzo?&#8230; Pues será algo parecido a la última viñeta de sus cómics, pero con un bonito del norte de 10 kilos para cada uno (si te quedas con hambre, siempre te podremos preparar un buen puchero de porrusalda).</p>\n\n\n\n<p>Y mientras terminas tu plato pensarás que<strong> no podrías estar en mejor lugar, rodeado de la mejor gente </strong>que te puedas encontrar&#8230; ¡Aivalaostia!&#8230; ¡Apúntatelo que se te va a ir el santo al cielo!&#8230; Recuerda, <strong>la WordCamp Bilbao 2025 será los días 10 y 11 de mayo, en As Fabrik</strong>.</p>\n\n\n\n<p>¡La mejor WordCamp del mundo!… Ni la de Europe, ni nada por el estilo… Eso son cosas de chiquillos.</p>\n\n\n\n<p><a href=\"https://bilbao.wordcamp.org/2025/comprar-entrada/\" target=\"_blank\" rel=\"noreferrer noopener\">Comprar entrada</a> </p>\n\n\n\n<h2 class=\"wp-block-heading\">Más contenido, más emoción, más comunidad</h2>\n\n\n\n<p>Tras la comida vendrán otras impresionantes charlas sobre <strong>SEO, maquetadores visuales, redes sociales, marketing</strong>…&nbsp;</p>\n\n\n\n<p>Y aquí es cuando me detengo, aunque me quede con muchas ganas de desvelarte la locura de After Party que habrá para los más atrevidos… Y me detengo para contarte lo que de verdad importa.&nbsp;</p>\n\n\n\n<p>Sí, ese “importa” al que me refería en los primeros párrafos del texto.</p>\n\n\n\n<p><a href=\"https://bilbao.wordcamp.org/2025/comprar-entrada/\" target=\"_blank\" rel=\"noreferrer noopener\">Comprar entrada</a> </p>\n\n\n\n<h2 class=\"wp-block-heading\">¿De verdad te lo vas a perder?</h2>\n\n\n\n<p>Tienes que venir a <strong>la WordCamp Bilbao</strong> porque realmente <strong>va a ser una WordCamp muy especial</strong>… Sí, ya sé que sabes que habrá <strong>networking del bueno</strong>, pero ¿sabes que lo harás rodeado de lo mejor de lo mejor?&nbsp;</p>\n\n\n\n<p>Sí… <strong>Eso tan bueno que encontrarás en Bilbao son las personas</strong> con las que te reencontrarás tras tiempo sin verlas en otros eventos; es la <strong>gente a la que pondrás por primera vez una cara física</strong> tras haber estado en contacto cientos de veces por streaming; es la <strong>ilusión que hará latir tu corazón</strong> al dar una ponencia o escucharla de los labios de ese ponente al que admiras; es…</p>\n\n\n\n<p>Y así, <strong>infinidad de emociones </strong>imposibles de describir sólo con palabras… Porque esas emociones sólo pueden ser descritas si decides formar parte de <strong>la comunidad WordPress</strong>, de <strong>esta gran cuadrilla de amigos</strong> que va a reunirse otro año más en Bilbao, de vivir <strong>una experiencia inolvidable</strong> en la ciudad más impresionante del mundo (espero que no me hagas repetirte por qué).</p>\n\n\n\n<p><a href=\"https://bilbao.wordcamp.org/2025/comprar-entrada/\" target=\"_blank\" rel=\"noreferrer noopener\">Comprar entrada</a> </p>\n\n\n\n<h2 class=\"wp-block-heading\">Trae el petate, nos vemos en Bilbao</h2>\n\n\n\n<p>Así que no te lo pienses mucho porque, de verdad (palabra de vasco), <strong>el 10 y 11 de mayo, en As Fabrik tendrá lugar la WordCamp Bilbao 2025</strong>… ¡La mejor WordCamp que podrás disfrutar en mucho tiempo! (hasta que hagamos la siguiente)</p>\n\n\n\n<p>Te estamos esperando.</p>\n\n\n\n<p><a href=\"https://bilbao.wordcamp.org/2025/comprar-entrada/\" target=\"_blank\" rel=\"noreferrer noopener\">Comprar entrada</a> </p>\n\n\n\n<p>PD.- Te habrás dado cuenta que al escribir este artículo he exagerado un pelín las cosas, pero solo eso (un pelín). Ya sabes, ¡así somos los de Bilbao!</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:88:\"https://es.wordpress.org/2025/04/29/wordcamp-bilbao-2025-que-viene-que-viene-eh-eh/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:6:\"687666\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:8;a:6:{s:4:\"data\";s:73:\"\n		\n		\n					\n		\n		\n		\n				\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:44:\"WordCamp Málaga 2025: IA, futuro, WordPress\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:77:\"https://es.wordpress.org/2025/04/17/wordcamp-malaga-2025-ia-futuro-wordpress/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:86:\"https://es.wordpress.org/2025/04/17/wordcamp-malaga-2025-ia-futuro-wordpress/#comments\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 17 Apr 2025 18:14:17 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"WordCamp\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://es.wordpress.org/?p=686519\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:143:\"WordCamp Málaga 2025 llega los días 26 y 27 de abril en Torremolinos con sol, playa, WordPress e Inteligencia Artificial. ¡No te la pierdas!\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:10:\"lualvarimp\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:5835:\"\n<p>Hay fechas en el calendario que tienen algo de especial y la <strong>WordCamp Málaga 2025, los días 26 y 27 de abril</strong>, sucede dentro de esas fechas mágicas…</p>\n\n\n\n<p>¿Por qué?&#8230; Porque justo sales de esa Semana Santa que tanto necesitas y, tras unos días de trabajo que se te harán muy pesados, ¿qué mejor que relajarse a la orilla del Mediterráneo con una WordCamp que te <strong>promete mucha IA y una visión futura de WordPress</strong> que no te esperas?</p>\n\n\n\n<p><a href=\"https://malaga.wordcamp.org/2025/entradas-wcmlg/\" target=\"_blank\" rel=\"noreferrer noopener\">Comprar mi entrada</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">Prepárate para lo inesperado</h2>\n\n\n\n<p>Te aseguro que esta gente va a montar un sarao del que se hablará durante mucho tiempo y… ¡Qué demonios!&#8230; Necesitas volver a <strong>despejar tu mente un par de días</strong> para volver a ser el crack que siempre has sido, pero que ha perdido un poco de fuelle desde principios de año…</p>\n\n\n\n<p>¡Eh!, sé que te viene el cansancio. Ya son cuatro meses en los que te has estado pegando con muchas webs, marketing y plugins que entran en conflicto entre sí… Aquellas cosas parecen chiringuitos mal montados, sin pies ni cabeza… ¡Y ese es el motivo por el que tienes que ir a Málaga!</p>\n\n\n\n<p><a href=\"https://malaga.wordcamp.org/2025/entradas-wcmlg/\" target=\"_blank\" rel=\"noreferrer noopener\">Comprar mi entrada</a></p>\n\n\n\n<p>Descubrirás unos chiringuitos muy bien montados en la playa de La Carihuela y en <strong>las instalaciones del Albergue Inturjoven Torremolinos, donde se celebrará el evento</strong>, te enseñarán a convertir ese caótico proyecto que tienes entre manos en una web digna de elogios, gracias a las herramientas de IA.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Mucho más de lo que te esperas</h2>\n\n\n\n<p>En la <strong>WordCamp Málaga 2025</strong> veremos mucho más que sol y playa, porque <strong>Torremolinos</strong>, ciudad donde la comunidad WordPress volverá a reunirse, es un lugar en el que se respira el espíritu emprendedor de sus habitantes.</p>\n\n\n\n<p>Aquí, la gente se busca la vida con ingenio y creatividad, igual que tú cada vez que intentas que ese chiringuito virtual contra el que te enfrentas día tras día se transforme en una web que funcione como la seda.</p>\n\n\n\n<p><a href=\"https://malaga.wordcamp.org/2025/entradas-wcmlg/\" target=\"_blank\" rel=\"noreferrer noopener\">Comprar mi entrada</a></p>\n\n\n\n<p>Así que venga… ¡Deja que el salitre te despeje las ideas y aprovecha el fin de semana para disfrutar con la <strong>comunidad WordPress</strong>!</p>\n\n\n\n<h2 class=\"wp-block-heading\">¿Y qué vas a encontrarte en esta WordCamp?</h2>\n\n\n\n<p>Pues unas <strong>charlas de infarto</strong> (sin necesidad de una RCP), unos <strong>talleres de quitar el hipo</strong> y un <strong>networking de primera</strong>… Conocerás a <strong>personas apasionadas de WordPress</strong>, intercambiarás ideas con gente que te sorprenderá y, quién sabe… Quizá te enamores de algún algoritmo sandunguero, generado por IA, mientras disfrutas de una cálida puesta de sol en la playa, con un rico espeto en la mano.</p>\n\n\n\n<p>En definitiva, que <strong>el buen rollo malagueño está garantizado</strong>, así que prepárate para reír, disfrutar y comer.</p>\n\n\n\n<p><a href=\"https://malaga.wordcamp.org/2025/entradas-wcmlg/\" target=\"_blank\" rel=\"noreferrer noopener\">Comprar mi entrada</a></p>\n\n\n\n<p>Y también prepárate para disfrutar de su cultura…</p>\n\n\n\n<p>Su cultura antigua, moderna y tecnológica… Sobre todo en esta última, en la que <strong>los organizadores de la WordCamp Málaga 2025 nos van a sorprender</strong> con unas ponencias que harán que tus páginas web sean mucho más eficientes gracias a la Inteligencia Artificial:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Marketing digital e IA</li>\n\n\n\n<li>IA y SEO</li>\n\n\n\n<li>Optimización emocional a través de la IA</li>\n\n\n\n<li>La revolución del vídeo con IA</li>\n\n\n\n<li>Creación de contenido con IA</li>\n\n\n\n<li>Automatizaciones usando IA</li>\n</ul>\n\n\n\n<p>Y mi favorita… IA para novatos…</p>\n\n\n\n<p><a href=\"https://malaga.wordcamp.org/2025/entradas-wcmlg/\" target=\"_blank\" rel=\"noreferrer noopener\">Comprar mi entrada</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">Una WordCamp para todos</h2>\n\n\n\n<p>“<strong>Una WordCamp para todos y todos para una</strong>” (en plan rollo “<em>Los tres mosqueteros</em>”, de Alejandro Dumas).</p>\n\n\n\n<p>Una de las cosas que más me gusta de una WordCamp es que es <strong>un evento que está hecho para ti</strong>, sin importar la cantidad o profundidad de conocimientos que poseas: <strong>siempre va a haber algo hecho a tu medida</strong>.</p>\n\n\n\n<p>Y en <strong>WordCamp Málaga 2025</strong> han tenido esto en cuenta y te ofrecen unas <strong>ponencias y unos talleres centrados en la Inteligencia Artificial</strong> y orientados a todos los públicos.</p>\n\n\n\n<p>Así que no te queda otra que prepararte para un festival de reencuentros, un aluvión de networking y un buen rollo que te dejará con la boca abierta (si es que has conseguido mantenerla cerrada en algún momento).</p>\n\n\n\n<p>Así que ya lo sabes, reserva <strong>los días 26 y 27 de abril</strong> en tu calendario y acércate a las instalaciones del <strong>Albergue Inturjoven Torremolinos</strong>, porque esta <strong>WordCamp Málaga 2025</strong> promete ser el <strong>eventazo de IA y WordPress</strong> que estabas esperando.</p>\n\n\n\n<p>Y además, estoy convencido que, al volver a casa, tras un fin de semana brutal junto a toda la <strong>comunidad WordPress</strong>, sueltas algo así como:<br>¡Qué bueno, illo! ¡Qué perita!</p>\n\n\n\n<p><a href=\"https://malaga.wordcamp.org/2025/entradas-wcmlg/\" target=\"_blank\" rel=\"noreferrer noopener\">Comprar mi entrada</a></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:82:\"https://es.wordpress.org/2025/04/17/wordcamp-malaga-2025-ia-futuro-wordpress/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"1\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:6:\"686519\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:9;a:6:{s:4:\"data\";s:76:\"\n		\n		\n					\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"WordPress 6.8 «Cecil»\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:56:\"https://es.wordpress.org/2025/04/15/wordpress-6-8-cecil/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:64:\"https://es.wordpress.org/2025/04/15/wordpress-6-8-cecil/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 15 Apr 2025 18:23:44 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:15:\"Actualizaciones\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:3:\"6.8\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://es.wordpress.org/?p=686506\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:379:\"Cada versión de WordPress rinde homenaje a un artista que ha dejado una huella indeleble en la música. WordPress 6.8, cuyo nombre en clave es «Cecil», rinde homenaje al legendario pianista y pionero del jazz Cecil Taylor. Taylor, de formación clásica pero implacablemente poco convencional, reinventó el piano como instrumento de percusión, combinando grupos de [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:16:\"Fernando Tellado\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:88296:\"\n<figure class=\"wp-block-image size-large\"><a href=\"https://es.wordpress.org/files/2025/04/WordPress-6-8-Cecil.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"535\" src=\"https://es.wordpress.org/files/2025/04/WordPress-6-8-Cecil-1024x535.jpg\" alt=\"\" class=\"wp-image-686507\" srcset=\"https://es.wordpress.org/files/2025/04/WordPress-6-8-Cecil-1024x535.jpg 1024w, https://es.wordpress.org/files/2025/04/WordPress-6-8-Cecil-300x157.jpg 300w, https://es.wordpress.org/files/2025/04/WordPress-6-8-Cecil-768x401.jpg 768w, https://es.wordpress.org/files/2025/04/WordPress-6-8-Cecil-1536x802.jpg 1536w, https://es.wordpress.org/files/2025/04/WordPress-6-8-Cecil-2048x1070.jpg 2048w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /></a></figure>\n\n\n\n<p>Cada versión de WordPress rinde homenaje a un artista que ha dejado una huella indeleble en la música. WordPress 6.8, cuyo nombre en clave es «Cecil», rinde homenaje al legendario pianista y pionero del jazz Cecil Taylor.</p>\n\n\n\n<p>Taylor, de formación clásica pero implacablemente poco convencional, reinventó el piano como instrumento de percusión, combinando grupos de tonos, polifonía y ritmo en un sonido caótico y preciso a la vez. Su música desafiaba las expectativas, encontrando forma en el desorden y armonía en la disonancia.</p>\n\n\n\n<p>Ese mismo espíritu impulsa WordPress 6.8. Adopta sus nuevas y atrevidas características con la misma curiosidad y experimentación que definieron el sonido de Cecil.</p>\n\n\n\n<h2 class=\"wp-block-heading\">¡Te damos la bienvenida a WordPress 6.8!</h2>\n\n\n\n<p>WordPress 6.8 pule y refina las herramientas que utilizas a diario, haciendo que tu sitio sea más rápido, más seguro y más fácil de gestionar.</p>\n\n\n\n<p>El libro de estilo ahora tiene un diseño estructurado y funciona con temas clásicos, lo que te da más control sobre los estilos globales.</p>\n\n\n\n<p>La carga especulativa acelera la navegación precargando los enlaces antes de que los usuarios naveguen hasta ellos, el hashing bcrypt refuerza la seguridad de las contraseñas automáticamente y las optimizaciones de las bases de datos mejoran el rendimiento.</p>\n\n\n\n<div class=\"wp-block-buttons is-layout-flex wp-block-buttons-is-layout-flex\">\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link wp-element-button\" href=\"https://es.wordpress.org/latest-es_ES.zip\" rel=\"nofollow\">Descarga ahora WordPress 6.8 «Cecil»</a></div>\n</div>\n\n\n\n<h2 class=\"wp-block-heading\">Una versión pulida hasta dejarla brillante.</h2>\n\n\n\n<h3 class=\"wp-block-heading\">El libro de estilo tiene un aspecto más limpio y algunos trucos nuevos</h3>\n\n\n\n<p>El libro de estilo tiene un nuevo diseño estructurado y etiquetas más claras, para que sea aún más fácil editar los colores, la tipografía -casi todos los estilos de tu sitio- en un solo lugar.</p>\n\n\n\n<p>Además, ahora puedes verlo en los temas clásicos que tienen editor de estilos o un archivo theme.json. Busca el&nbsp;libro de estilo&nbsp;en «Apariencia &gt; Diseño» y utilízalo para previsualizar la evolución de tu tema a medida que editas CSS o realizas cambios en el personalizador.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><a href=\"https://es.wordpress.org/files/2025/04/6-8-style-book.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"900\" height=\"900\" src=\"https://es.wordpress.org/files/2025/04/6-8-style-book.jpg\" alt=\"\" class=\"wp-image-686508\" srcset=\"https://es.wordpress.org/files/2025/04/6-8-style-book.jpg 900w, https://es.wordpress.org/files/2025/04/6-8-style-book-300x300.jpg 300w, https://es.wordpress.org/files/2025/04/6-8-style-book-150x150.jpg 150w, https://es.wordpress.org/files/2025/04/6-8-style-book-768x768.jpg 768w\" sizes=\"auto, (max-width: 900px) 100vw, 900px\" /></a></figure>\n\n\n\n<h3 class=\"wp-block-heading\">Mejoras en el editor</h3>\n\n\n\n<p>Es más fácil ver las opciones en las vistas de datos y puedes excluir las entradas fijas de la consulta de contenidos. </p>\n\n\n\n<p>Además, encontrarás un montón de pequeñas mejoras en el editor que te facilitarán el camino en todo lo que crees.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><a href=\"https://es.wordpress.org/files/2025/04/6-8-editor-improvements.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"900\" height=\"900\" src=\"https://es.wordpress.org/files/2025/04/6-8-editor-improvements.jpg\" alt=\"\" class=\"wp-image-686509\" srcset=\"https://es.wordpress.org/files/2025/04/6-8-editor-improvements.jpg 900w, https://es.wordpress.org/files/2025/04/6-8-editor-improvements-300x300.jpg 300w, https://es.wordpress.org/files/2025/04/6-8-editor-improvements-150x150.jpg 150w, https://es.wordpress.org/files/2025/04/6-8-editor-improvements-768x768.jpg 768w\" sizes=\"auto, (max-width: 900px) 100vw, 900px\" /></a></figure>\n\n\n\n<h3 class=\"wp-block-heading\">Carga de páginas casi instantánea gracias a la carga especulativa</h3>\n\n\n\n<p>En WordPress 6.8 las páginas se cargan más rápido que nunca. </p>\n\n\n\n<p>Cuando tú o tu usuario pasáis el cursor sobre un enlace o hacéis clic en él, WordPress puede precargar la página siguiente, para que la experiencia sea más fluida y casi instantánea. </p>\n\n\n\n<p>El sistema equilibra velocidad y eficiencia, y puedes controlar cómo funciona, con un plugin o con tu propio código. </p>\n\n\n\n<p>Esta característica sólo funciona en los navegadores modernos; los antiguos simplemente la ignorarán sin ningún impacto.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><a href=\"https://es.wordpress.org/files/2025/04/6-8-speculative-loading-1.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"900\" height=\"900\" src=\"https://es.wordpress.org/files/2025/04/6-8-speculative-loading-1.jpg\" alt=\"\" class=\"wp-image-686510\" srcset=\"https://es.wordpress.org/files/2025/04/6-8-speculative-loading-1.jpg 900w, https://es.wordpress.org/files/2025/04/6-8-speculative-loading-1-300x300.jpg 300w, https://es.wordpress.org/files/2025/04/6-8-speculative-loading-1-150x150.jpg 150w, https://es.wordpress.org/files/2025/04/6-8-speculative-loading-1-768x768.jpg 768w\" sizes=\"auto, (max-width: 900px) 100vw, 900px\" /></a></figure>\n\n\n\n<h3 class=\"wp-block-heading\">Mayor seguridad de las contraseñas con bcrypt</h3>\n\n\n\n<p>Ahora las contraseñas son más difíciles de descifrar con el algoritmo bcrypt, que requiere mucha más potencia de cálculo. </p>\n\n\n\n<p>Esto refuerza la seguridad general, al igual que otras mejoras de cifrado en WordPress. </p>\n\n\n\n<p>No tienes que hacer nada: todo se actualiza automáticamente.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><a href=\"https://es.wordpress.org/files/2025/04/6-8-stronger-password-security-bcrypt.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"900\" height=\"900\" src=\"https://es.wordpress.org/files/2025/04/6-8-stronger-password-security-bcrypt.jpg\" alt=\"\" class=\"wp-image-686511\" srcset=\"https://es.wordpress.org/files/2025/04/6-8-stronger-password-security-bcrypt.jpg 900w, https://es.wordpress.org/files/2025/04/6-8-stronger-password-security-bcrypt-300x300.jpg 300w, https://es.wordpress.org/files/2025/04/6-8-stronger-password-security-bcrypt-150x150.jpg 150w, https://es.wordpress.org/files/2025/04/6-8-stronger-password-security-bcrypt-768x768.jpg 768w\" sizes=\"auto, (max-width: 900px) 100vw, 900px\" /></a></figure>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\" />\n\n\n\n<h3 class=\"wp-block-heading\">Mejoras de accesibilidad</h3>\n\n\n\n<p>Más de 100 correcciones y mejoras de accesibilidad afectan a un amplio espectro de la experiencia de WordPress. </p>\n\n\n\n<p>Esta versión incluye correcciones en todos los temas incluidos, mejoras en la gestión del menú de navegación, en el personalizador y en el etiquetado simplificado. </p>\n\n\n\n<p>El editor de bloques incluye más de 70 mejoras en bloques, vistas de datos y en la experiencia general del usuario.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Mejoras de rendimiento</h3>\n\n\n\n<p>WordPress 6.8 incluye una amplia gama de correcciones y mejoras de rendimiento para acelerar todo, desde la edición hasta la navegación. </p>\n\n\n\n<p>Además de la carga especulativa, WordPress 6.8 presta especial atención al editor de bloques, al registro de tipos de bloque y al almacenamiento en caché de consultas. Además, imagina no tener que esperar más de 50 milisegundos para cualquier interacción. </p>\n\n\n\n<p>En WordPress 6.8, la API de interactividad da un primer paso hacia ese objetivo.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Y mucho más</h3>\n\n\n\n<p>Para obtener una visión general de todas las nuevas características y mejoras de WordPress 6.8, visita el sitio web de presentación de características.</p>\n\n\n\n<div class=\"wp-block-buttons is-layout-flex wp-block-buttons-is-layout-flex\">\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link wp-element-button\" href=\"https://wordpress.org/download/releases/6-8/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">Ver todas las novedades</a></div>\n</div>\n\n\n\n<h2 class=\"wp-block-heading\">Más información de WordPress 6.8</h2>\n\n\n\n<p><a href=\"https://learn.wordpress.org/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">Aprende WordPress</a>&nbsp;es un recurso gratuito para los usuarios de WordPress, tanto los nuevos como los experimentados.&nbsp;</p>\n\n\n\n<p>Está repleto de vídeos sobre cómo utilizar las distintas características de WordPress,&nbsp;<a href=\"https://learn.wordpress.org/online-workshops/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">eventos interactivos</a>&nbsp;para explorar temáticas en profundidad, y planes de lecciones para sumergirse en áreas específicas de WordPress.</p>\n\n\n\n<p>Lee las&nbsp;<a href=\"https://wordpress.org/documentation/wordpress-version/version-6.8\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">notas de la versión de WordPress 6.8</a>&nbsp;para obtener información sobre la instalación, las mejoras, los problemas corregidos, los colaboradores de la versión, los recursos de aprendizaje y la lista de cambios en los archivos.</p>\n\n\n\n<p>Explora la&nbsp;<a href=\"https://make.wordpress.org/core/2025/03/28/wordpress-6-8-field-guide/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">guía de campo de WordPress 6.8</a>. Infórmate sobre los cambios en esta versión con notas detalladas para desarrolladores que te ayudarán a construir con WordPress.</p>\n\n\n\n<h2 class=\"wp-block-heading\">El equipo de la versión 6.8</h2>\n\n\n\n<p>Cada versión viene de la mano de un equipo de colaboradores entusiastas que ayudan a mantener el rumbo y la fluidez.</p>\n\n\n\n<p>El equipo que ha liderado la versión 6.8 es un grupo multidisciplinar de colaboradores siempre dispuestos a defender ideas, eliminar obstáculos y resolver problemas.</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Líder de la versión:&nbsp;<a href=\"https://profiles.wordpress.org/matt/\">Matt Mullenweg</a></li>\n\n\n\n<li>Coordinación de la versión:&nbsp;<a href=\"https://profiles.wordpress.org/jeffpaul/\">Jeffrey Paul</a>&nbsp;y&nbsp;<a href=\"https://profiles.wordpress.org/michelleames/\">Michelle Frechette</a></li>\n\n\n\n<li>Líderes técnicos:&nbsp;<a href=\"https://profiles.wordpress.org/joemcgill/\">Joe McGill</a>,&nbsp;<a href=\"https://profiles.wordpress.org/desrosj/\">Jonathan Desrosiers</a> y&nbsp;<a href=\"https://profiles.wordpress.org/mamaduka/\">George Mamadashvili</a></li>\n\n\n\n<li>Líder de triaje:&nbsp;<a href=\"https://profiles.wordpress.org/audrasjb/\">Jb Audras</a></li>\n\n\n\n<li>Líder de diseño:&nbsp;<a href=\"https://profiles.wordpress.org/karmatosed/\">Tammie Lister</a></li>\n\n\n\n<li>Líder de rendimiento:&nbsp;<a href=\"https://profiles.wordpress.org/flixos90/\">Felix Arntz</a></li>\n\n\n\n<li>Líder de pruebas:&nbsp;<a href=\"https://profiles.wordpress.org/krupajnanda/\">Krupa Nanda</a></li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\">¡Gracias, colaboradores!</h2>\n\n\n\n<p>La misión de WordPress es&nbsp;<a href=\"https://wordpress.org/about/\" target=\"_blank\" rel=\"noreferrer noopener\">democratizar la publicación</a>&nbsp;y encarnar las&nbsp;<a href=\"https://opensource.org/osd-annotated\" target=\"_blank\" rel=\"noreferrer noopener\">libertades que ofrece el código abierto</a>&nbsp;. Una comunidad global y diversa de personas que colaboran para fortalecer el software respalda este esfuerzo.</p>\n\n\n\n<p>WordPress 6.8 refleja el esfuerzo incansable y la pasión de más de 900 colaboradores de más de 60 países de todo el mundo. ¡Esta versión también dio la bienvenida a más de 250 colaboradores nuevos!</p>\n\n\n\n<p>Su colaboración produjo más de 320 mejoras y correcciones, garantizando una versión estable para todos, un testimonio del potencial y la capacidad de la comunidad de código abierto de WordPress.</p>\n\n\n\n<p class=\"alignfull has-white-color has-blueberry-2-background-color has-text-color has-background has-link-color wp-elements-0400fc6b31be42dc4c0f0f5dea78c8fa\"><a href=\"https://profiles.wordpress.org/jorbin/\">Aaron Jorbin</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/aaronrobertshaw/\">Aaron Robertshaw</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/thehercules/\">Aashish Sharma</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/webcommsat/\">Abha Thakor</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/hiabhaykulkarni/\">Abhay Kulkarni</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/abhi3315/\">abhi3315</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/adakaleh/\">AdaKaleh</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/adamsilverstein/\">Adam Silverstein</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/zieladam/\">Adam Zieliński</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/adhun/\">Adhun Anand</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/adityab98/\">Aditya Bansode</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/stromhalm/\">Adrian Jagusch</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/aduth/\">aduth</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/hemant-ahir/\">Ahir Hemant</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/ahmarzaidi/\">Ahmar Zaidi</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/chaion07/\">Ahmed Kabir Chaion</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/engahmeds3ed/\">Ahmed Saeed</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/ahsankhan316/\">Ahsan Khan</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/aishwarryapande/\">Aishwarrya Pande</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/ajayghaghretiya1/\">Ajay Ghaghretiya</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/ajmaurya/\">Ajay Maurya</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/ajitbohra/\">Ajit Bohra</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/akanshusingh/\">Akanshu Singh</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/wildworks/\">Aki Hamano</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/atachibana/\">Akira Tachibana</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/aks30498/\">aks30498</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/akshat2802/\">Akshat Kakkad</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/akshaydhere/\">Akshay Dhere</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/aljullu/\">Albert Juhé Lluveras</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/ralessio/\">Alessio</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/xknown/\">Alex Concha</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/alexflorisca/\">Alex Florisca</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/ajlende/\">Alex Lende</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/alexstine/\">Alex Stine</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/albigdd/\">Alexander Bigga</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/alexandrebuffet/\">Alexandre Buffet</a>&nbsp;·&nbsp;<a href=\"https://pro